/* Freestanding fixed-width integer and basic type definitions. */
#ifndef _KERNEL_TYPES_H
#define _KERNEL_TYPES_H

typedef unsigned char      u8;
typedef unsigned short     u16;
typedef unsigned int       u32;
typedef unsigned long long u64;
typedef signed char        i8;
typedef short              i16;
typedef int                i32;
typedef long long          i64;

typedef unsigned long      uintptr_t;
typedef long               intptr_t;
typedef unsigned long      size_t;
typedef long               ssize_t;
typedef long               off_t;

#ifndef NULL
#define NULL ((void *)0)
#endif

typedef _Bool bool;
#define true  1
#define false 0

#endif /* _KERNEL_TYPES_H */

/* Process / thread model and scheduler interface. */
#ifndef _KERNEL_PROC_H
#define _KERNEL_PROC_H

#include "kernel/types.h"
#include "kernel/param.h"

/* Callee-saved register set switched by swtch() (arch/<arch>/swtch.S).
 * Layout MUST match the assembly: ra @0, sp @8, s0..s11 @16.. */
struct context {
    u64 ra;
    u64 sp;
    u64 s[12];
};

/* User trap frame. Field offsets MUST match arch/riscv/trampoline.S. */
struct trapframe {
    /*   0 */ u64 kernel_satp;
    /*   8 */ u64 kernel_sp;
    /*  16 */ u64 kernel_trap;   /* usertrap() address */
    /*  24 */ u64 epc;
    /*  32 */ u64 kernel_hartid;
    /*  40 */ u64 ra;
    /*  48 */ u64 sp;
    /*  56 */ u64 gp;
    /*  64 */ u64 tp;
    /*  72 */ u64 t0;
    /*  80 */ u64 t1;
    /*  88 */ u64 t2;
    /*  96 */ u64 s0;
    /* 104 */ u64 s1;
    /* 112 */ u64 a0;
    /* 120 */ u64 a1;
    /* 128 */ u64 a2;
    /* 136 */ u64 a3;
    /* 144 */ u64 a4;
    /* 152 */ u64 a5;
    /* 160 */ u64 a6;
    /* 168 */ u64 a7;
    /* 176 */ u64 s2;
    /* 184 */ u64 s3;
    /* 192 */ u64 s4;
    /* 200 */ u64 s5;
    /* 208 */ u64 s6;
    /* 216 */ u64 s7;
    /* 224 */ u64 s8;
    /* 232 */ u64 s9;
    /* 240 */ u64 s10;
    /* 248 */ u64 s11;
    /* 256 */ u64 t3;
    /* 264 */ u64 t4;
    /* 272 */ u64 t5;
    /* 280 */ u64 t6;
};

typedef u64 *pagetable_t;

enum procstate { UNUSED, USED, SLEEPING, RUNNABLE, RUNNING, ZOMBIE };

struct vma {
    u64 start;
    u64 end;
    int shared;
    int perm;
    int shmid;
};

struct proc {
    enum procstate state;
    int            pid;
    int            tgid;
    int            pgid;
    int            sid;
    int            uid;
    int            euid;
    int            gid;
    int            egid;
    u16            umask;
    int            ngroups;
    u32            groups[8];
    char           name[16];
    u64            kstack;          /* bottom of the kernel stack */
    struct context ctx;            /* swtch() target */
    void         (*entry)(void);   /* kernel-thread entry (phase 1) */
    void          *chan;            /* sleep channel */
    int            xstate;          /* exit status */
    int            killed;

    /* User process state (phase 2+). */
    pagetable_t       pagetable;   /* user page table, or NULL for kthreads */
    struct trapframe *trapframe;   /* user registers, mapped at TRAPFRAME */
    u64               sz;          /* size of user memory image */
    u64               brk;         /* current program break (heap top) */
    u64               mmap_top;    /* next anonymous mmap base (grows down) */
    int               is_thread;
    u64               clear_child_tid;
    struct proc      *parent;      /* creating process */
    struct file      *ofile[NOFILE]; /* open file descriptors */
    char              cwd[128];    /* current working directory (absolute) */
    struct vma        vmas[NVMA];
};

struct file;

/* One per CPU (single-hart for now). */
struct cpu {
    struct proc   *proc;           /* running process, or NULL */
    struct context ctx;            /* scheduler context */
    int            noff;           /* depth of intr-off nesting */
    int            intena;         /* were interrupts enabled before push_off */
};

struct cpu  *mycpu(void);
struct proc *myproc(void);
struct proc *proc_find(int pid);
int          proc_pgrp_exists(int sid, int pgid);
int          proc_kill(int pid, int sig);
int          proc_handle_page_fault(u64 va);

void proc_init(void);
struct proc *kthread_create(void (*fn)(void), const char *name);
struct proc *proc_alloc(void);          /* grab an UNUSED slot, assign pid */
void         proc_exit(int code) __attribute__((noreturn));
void         proc_exit_signal(int sig) __attribute__((noreturn));
int          exec_user(const char *path, char *const argv[], char *const envp[]);
int          exec_replace(const char *path, char *const argv[], char *const envp[]);
int          fork(void);
int          clone(u64 flags, u64 newsp, u64 ptid, u64 tls, u64 ctid);
int          wait4(int pid, u64 ustatus, int options);
struct proc *proc_initproc(void);
int          exec_user_cwd(const char *path, char *const argv[],
                           char *const envp[], const char *cwd);
void         proc_free_user_image(pagetable_t pt, u64 sz, u64 mmap_top);
void scheduler(void);   /* returns when no thread can run (phase 1) */
void sched(void);
void yield(void);
void kthread_exit(void) __attribute__((noreturn));

void sleep(void *chan);
void wakeup(void *chan);
int  wakeup_n(void *chan, int max);

/* arch context switch: save current -> old, load new. */
void swtch(struct context *old, struct context *new);

/* Phase-1 demonstration: spawn kernel threads and run the scheduler. */
void phase1_demo(void);

#endif /* _KERNEL_PROC_H */

/* Virtual-memory and user-trap interface (RISC-V implementation in arch/riscv).
 * Page permission bits use the RISC-V Sv39 PTE encoding. */
#ifndef _KERNEL_VM_H
#define _KERNEL_VM_H

#include "kernel/types.h"
#include "kernel/proc.h"

#define PERM_R (1 << 1)
#define PERM_W (1 << 2)
#define PERM_X (1 << 3)
#define PERM_U (1 << 4)

int         mappages(pagetable_t pt, u64 va, u64 size, u64 pa, int perm);
u64         walkaddr(pagetable_t pt, u64 va);
pagetable_t uvmcreate(void);
u64         uvmalloc(pagetable_t pt, u64 oldsz, u64 newsz, int perm);
void        uvmunmap(pagetable_t pt, u64 va, u64 npages, int do_free);
void        uvmfree(pagetable_t pt, u64 sz);
int         copyout(pagetable_t pt, u64 dstva, const void *src, u64 len);
int         copyin(pagetable_t pt, void *dst, u64 srcva, u64 len);
int         uvmcopy(pagetable_t old, pagetable_t new, u64 start, u64 end);
int         uvmcopy_cow(pagetable_t old, pagetable_t new, u64 start, u64 end);
int         uvmcopy_page(pagetable_t old, pagetable_t new, u64 va);
int         uvmshare_page(pagetable_t old, pagetable_t new, u64 va);
int         uvmcow(pagetable_t pt, u64 va);
int         uvmprotect(pagetable_t pt, u64 va, u64 len, int perm,
                       int alloc_missing);

pagetable_t proc_pagetable(struct proc *p);
void        proc_freepagetable(pagetable_t pt, u64 sz);

void        usertrap(void);
void        usertrapret(void);
void        forkret(void);

#endif /* _KERNEL_VM_H */

/* Memory management: physical frame allocator + kernel heap. */
#ifndef _KERNEL_MM_H
#define _KERNEL_MM_H

#include "kernel/types.h"

/* Physical frame allocator (4 KiB pages). */
void  pmm_init(u64 ram_start, u64 ram_end);
void *kalloc_page(void);   /* one zeroed 4 KiB page, or NULL */
void  kref_page(void *pa);
void  kfree_page(void *pa);
u64   pmm_free_pages(void); /* count of free frames (diagnostics) */

/* Kernel heap. */
void  kheap_init(void);
void *kmalloc(size_t n);
void *kzalloc(size_t n);
void  kfree(void *p);

#endif /* _KERNEL_MM_H */

/* RISC-V supervisor-mode register and CSR helpers. */
#ifndef _KERNEL_RISCV_H
#define _KERNEL_RISCV_H

#include "kernel/types.h"

/* sstatus bits */
#define SSTATUS_SIE  (1UL << 1)   /* supervisor interrupt enable */
#define SSTATUS_SPIE (1UL << 5)   /* prior SIE before trap */
#define SSTATUS_SPP  (1UL << 8)   /* prior privilege (1 = supervisor) */
#define SSTATUS_SUM  (1UL << 18)  /* permit S-mode access to U-mode pages */

/* sie / sip bits */
#define SIE_SSIE (1UL << 1)
#define SIE_STIE (1UL << 5)
#define SIE_SEIE (1UL << 9)

/* scause */
#define SCAUSE_INT      (1UL << 63)
#define IRQ_S_SOFT      1
#define IRQ_S_TIMER     5
#define IRQ_S_EXT       9

/* satp */
#define SATP_SV39 (8UL << 60)
#define MAKE_SATP(pa) (SATP_SV39 | ((u64)(pa) >> 12))

/* Sv39 PTE flag bits */
#define PTE_V (1UL << 0)
#define PTE_R (1UL << 1)
#define PTE_W (1UL << 2)
#define PTE_X (1UL << 3)
#define PTE_U (1UL << 4)
#define PTE_G (1UL << 5)
#define PTE_A (1UL << 6)
#define PTE_D (1UL << 7)
#define PTE_COW (1UL << 8)

#define CSRR(reg) ({ u64 __v; asm volatile("csrr %0, " reg : "=r"(__v)); __v; })
#define CSRW(reg, val) ({ u64 __v = (u64)(val); asm volatile("csrw " reg ", %0" :: "r"(__v)); })

static inline u64 r_sstatus(void) { return CSRR("sstatus"); }
static inline void w_sstatus(u64 x) { CSRW("sstatus", x); }
static inline u64 r_sie(void) { return CSRR("sie"); }
static inline void w_sie(u64 x) { CSRW("sie", x); }
static inline u64 r_sip(void) { return CSRR("sip"); }
static inline void w_sip(u64 x) { CSRW("sip", x); }
static inline u64 r_scause(void) { return CSRR("scause"); }
static inline u64 r_sepc(void) { return CSRR("sepc"); }
static inline void w_sepc(u64 x) { CSRW("sepc", x); }
static inline u64 r_stval(void) { return CSRR("stval"); }
static inline void w_stvec(u64 x) { CSRW("stvec", x); }
static inline void w_satp(u64 x) { CSRW("satp", x); }
static inline u64 r_satp(void) { return CSRR("satp"); }
static inline u64 r_time(void) { return CSRR("time"); }

static inline void intr_on(void)  { w_sstatus(r_sstatus() | SSTATUS_SIE); }
static inline void intr_off(void) { w_sstatus(r_sstatus() & ~SSTATUS_SIE); }
static inline int  intr_get(void) { return (r_sstatus() & SSTATUS_SIE) != 0; }

static inline void sfence_vma(void) { asm volatile("sfence.vma zero, zero"); }

#endif /* _KERNEL_RISCV_H */

/* ELF64 loader interface. */
#ifndef _KERNEL_ELF_H
#define _KERNEL_ELF_H

#include "kernel/types.h"
#include "kernel/proc.h"

struct elf_info {
    u64 entry;       /* image entry point */
    u64 aux_entry;   /* AT_ENTRY for the main executable */
    u64 at_base;     /* AT_BASE for the dynamic linker */
    u64 base;        /* load bias used for ET_DYN */
    u64 sz;          /* highest user VA used by the image */
    u64 phdr;        /* VA of the program headers (for AT_PHDR) */
    u16 phnum;       /* AT_PHNUM */
    u16 phent;       /* AT_PHENT */
    char interp[128]; /* PT_INTERP path, empty for static executables */
};

#define ELF_MAIN_BASE   0x20000000UL
#define ELF_INTERP_BASE 0x40000000UL

int elf_load(pagetable_t pt, const u8 *elf, u64 elflen,
             u64 dyn_base, struct elf_info *info);

#endif /* _KERNEL_ELF_H */
/* Linux-compatible negative errno values returned by syscalls. */
#ifndef _KERNEL_ERRNO_H
#define _KERNEL_ERRNO_H

#define EPERM    1
#define ENOENT   2
#define ESRCH    3
#define EINTR    4
#define EIO      5
#define ENOEXEC  8
#define EBADF    9
#define ECHILD  10
#define EAGAIN  11
#define ENOMEM  12
#define EACCES  13
#define EFAULT  14
#define EBUSY   16
#define EEXIST  17
#define ENODEV  19
#define ENOTDIR 20
#define EISDIR  21
#define EINVAL  22
#define EMFILE  24
#define ENOTTY  25
#define ENOSPC  28
#define ESPIPE  29
#define EPIPE   32
#define EPROTONOSUPPORT 93
#define EOPNOTSUPP 95
#define ERANGE  34
#define ENOSYS  38
#define ENOTEMPTY 39
#define EAFNOSUPPORT 97
#define EADDRINUSE 98
#define ECONNREFUSED 111

#endif /* _KERNEL_ERRNO_H */
/* Low-level console / platform I/O provided per architecture. */
#ifndef _KERNEL_KIO_H
#define _KERNEL_KIO_H

#include "kernel/types.h"

/* Implemented per architecture (arch/<arch>/sbi.c or power.c + uart driver). */
void     arch_early_init(u64 hartid, u64 dtb);  /* bring up console etc. */
void     uart_putc(char c);                     /* blocking serial output */
int      uart_getc(void);                        /* -1 if no input */
void     arch_shutdown(void) __attribute__((noreturn));
void     arch_halt(void) __attribute__((noreturn));
const char *arch_name(void);

/* Arch-neutral interrupt control (used by the portable kernel core). */
void     arch_intr_on(void);
void     arch_intr_off(void);
int      arch_intr_get(void);
void     arch_idle(void);    /* wait for interrupt (wfi / idle) */

#endif /* _KERNEL_KIO_H */
/* Compiler attribute helpers. */
#ifndef _KERNEL_COMPILER_H
#define _KERNEL_COMPILER_H

#define likely(x)   __builtin_expect(!!(x), 1)
#define unlikely(x) __builtin_expect(!!(x), 0)

#define __packed    __attribute__((packed))
#define __aligned(n) __attribute__((aligned(n)))
#define __noreturn  __attribute__((noreturn))
#define __unused    __attribute__((unused))

#define container_of(ptr, type, member) \
    ((type *)((char *)(ptr) - __builtin_offsetof(type, member)))

#define ARRAY_SIZE(a) (sizeof(a) / sizeof((a)[0]))

#endif /* _KERNEL_COMPILER_H */
/* Kernel virtual <-> physical address helpers. */
#ifndef _KERNEL_ADDR_H
#define _KERNEL_ADDR_H

#include "kernel/types.h"

#ifdef ARCH_LOONGARCH
#define LA_DMW0_BASE 0x9000000000000000UL
#define LA_DMW_MASK  0x0fffffffffffffffUL

static inline u64 kva_to_pa(u64 kva)
{
    return kva & LA_DMW_MASK;
}

static inline void *pa_to_kva(u64 pa)
{
    return (void *)(pa | LA_DMW0_BASE);
}
#else
static inline u64 kva_to_pa(u64 kva)
{
    return kva;
}

static inline void *pa_to_kva(u64 pa)
{
    return (void *)pa;
}
#endif

#endif /* _KERNEL_ADDR_H */
/* Trap / interrupt setup (arch-specific implementation). */
#ifndef _KERNEL_TRAP_H
#define _KERNEL_TRAP_H

#include "kernel/types.h"

void trap_init(void);        /* install kernel trap vector, enable interrupts src */
void timer_init(void);       /* arm the periodic timer */
void timer_tick(void);       /* called from the trap handler on each tick */

extern volatile u64 g_ticks; /* monotonically increasing tick counter */

int  dev_intr(u64 scause);   /* 2=timer, 1=other, 0=not a device interrupt */

/* arch vector entry (assembly). */
void kernelvec(void);

#endif /* _KERNEL_TRAP_H */
/* Kernel formatted output. */
#ifndef _KERNEL_PRINTK_H
#define _KERNEL_PRINTK_H

#include "kernel/types.h"
#include "kernel/compiler.h"

void printk(const char *fmt, ...) __attribute__((format(printf, 1, 2)));
int  vsnprintk(char *buf, size_t size, const char *fmt, __builtin_va_list ap);
int  snprintk(char *buf, size_t size, const char *fmt, ...)
    __attribute__((format(printf, 3, 4)));

void panic(const char *fmt, ...) __attribute__((noreturn, format(printf, 1, 2)));

#define BUG_ON(cond) do { if (unlikely(cond)) panic("BUG_ON(%s) at %s:%d", #cond, __FILE__, __LINE__); } while (0)
#define assert(cond) BUG_ON(!(cond))

#endif /* _KERNEL_PRINTK_H */

/* LoongArch64 CSR helpers and constants used by the arch port. */
#ifndef _KERNEL_LOONGARCH_H
#define _KERNEL_LOONGARCH_H

#include "kernel/types.h"

#define LOONGARCH_CSR_CRMD       0x0
#define LOONGARCH_CSR_PRMD       0x1
#define LOONGARCH_CSR_EUEN       0x2
#define LOONGARCH_CSR_ECFG       0x4
#define LOONGARCH_CSR_ESTAT      0x5
#define LOONGARCH_CSR_ERA        0x6
#define LOONGARCH_CSR_BADV       0x7
#define LOONGARCH_CSR_EENTRY     0xc
#define LOONGARCH_CSR_ASID       0x18
#define LOONGARCH_CSR_PGDL       0x19
#define LOONGARCH_CSR_PGDH       0x1a
#define LOONGARCH_CSR_PWCL       0x1c
#define LOONGARCH_CSR_PWCH       0x1d
#define LOONGARCH_CSR_STLBPS     0x1e
#define LOONGARCH_CSR_SAVE0      0x30
#define LOONGARCH_CSR_SAVE1      0x31
#define LOONGARCH_CSR_TCFG       0x41
#define LOONGARCH_CSR_TICLR      0x44
#define LOONGARCH_CSR_TLBRENTRY  0x88

#define CRMD_PLV_MASK 0x3UL
#define CRMD_IE       (1UL << 2)
#define CRMD_DA       (1UL << 3)
#define CRMD_PG       (1UL << 4)

#define PRMD_PPLV3    3UL
#define PRMD_PIE      (1UL << 2)

#define EUEN_FPE      (1UL << 0)

#define ECFG_TIMER    (1UL << 11)
#define ESTAT_TIMER   (1UL << 11)
#define ESTAT_ECODE(x) (((x) >> 16) & 0x3f)
#define EXCCODE_INT   0
#define EXCCODE_SYS   11

#define TCFG_EN       (1UL << 0)
#define TCFG_PERIODIC (1UL << 1)

#define DMW_PLV0      (1UL << 0)
#define DMW_MAT_CC    (1UL << 4)
#define DMW_VSEG9     (9UL << 60)

#define __CSR_STR(x) #x
#define CSR_STR(x) __CSR_STR(x)

#define csr_read(csr) ({ \
    u64 __v; \
    asm volatile("csrrd %0, " CSR_STR(csr) : "=r"(__v)); \
    __v; \
})

#define csr_write(csr, val) do { \
    u64 __v = (u64)(val); \
    asm volatile("csrwr %0, " CSR_STR(csr) : "+r"(__v)); \
} while (0)

static inline u64 r_crmd(void) { return csr_read(LOONGARCH_CSR_CRMD); }
static inline void w_crmd(u64 x) { csr_write(LOONGARCH_CSR_CRMD, x); }
static inline u64 r_ecfg(void) { return csr_read(LOONGARCH_CSR_ECFG); }
static inline void w_ecfg(u64 x) { csr_write(LOONGARCH_CSR_ECFG, x); }
static inline void w_euen(u64 x) { csr_write(LOONGARCH_CSR_EUEN, x); }
static inline u64 r_estat(void) { return csr_read(LOONGARCH_CSR_ESTAT); }
static inline u64 r_era(void) { return csr_read(LOONGARCH_CSR_ERA); }
static inline void w_era(u64 x) { csr_write(LOONGARCH_CSR_ERA, x); }
static inline u64 r_badv(void) { return csr_read(LOONGARCH_CSR_BADV); }
static inline void w_eentry(u64 x) { csr_write(LOONGARCH_CSR_EENTRY, x); }
static inline void w_tlbrentry(u64 x) { csr_write(LOONGARCH_CSR_TLBRENTRY, x); }
static inline void w_prmd(u64 x) { csr_write(LOONGARCH_CSR_PRMD, x); }
static inline void w_asid(u64 x) { csr_write(LOONGARCH_CSR_ASID, x); }
static inline void w_pgdl(u64 x) { csr_write(LOONGARCH_CSR_PGDL, x); }
static inline void w_pgdh(u64 x) { csr_write(LOONGARCH_CSR_PGDH, x); }
static inline void w_pwcl(u64 x) { csr_write(LOONGARCH_CSR_PWCL, x); }
static inline void w_pwch(u64 x) { csr_write(LOONGARCH_CSR_PWCH, x); }
static inline void w_stlbps(u64 x) { csr_write(LOONGARCH_CSR_STLBPS, x); }
static inline void w_save0(u64 x) { csr_write(LOONGARCH_CSR_SAVE0, x); }
static inline void w_save1(u64 x) { csr_write(LOONGARCH_CSR_SAVE1, x); }
static inline void w_tcfg(u64 x) { csr_write(LOONGARCH_CSR_TCFG, x); }
static inline void w_ticlr(u64 x) { csr_write(LOONGARCH_CSR_TICLR, x); }

static inline void loongarch_invtlb_all(void)
{
    asm volatile("invtlb 0x0, $r0, $r0" ::: "memory");
}

#endif /* _KERNEL_LOONGARCH_H */

/* Open-file objects and the in-RAM scratch filesystem (ramfs).
 *
 * Phase 3 supports: console devices (fd 0/1/2), read-only ext4 inodes, blocking
 * pipes, and a small writable ramfs so tests that create files/dirs work.
 */
#ifndef _FS_FILE_H
#define _FS_FILE_H

#include "kernel/types.h"
#include "kernel/param.h"

struct kstat;
struct pipe;

#define RAMFS_FILE_CAP   (8UL * 1024 * 1024)
#define RAMFS_MAX_PAGES  (RAMFS_FILE_CAP / PGSIZE)

/* In-RAM scratch file/dir node, keyed by absolute path. */
struct ramnode {
    char path[128];
    int  is_dir;
    int  is_symlink;
    int  used;
    u16  mode;
    char target[128];
    u8  *pages[RAMFS_MAX_PAGES];
    u64  size;
};

enum file_type { FD_NONE, FD_DEVICE, FD_INODE, FD_RAMFS, FD_PIPE, FD_SOCKET };

enum file_device {
    DEV_CONSOLE = 0,
    DEV_NULL,
    DEV_ZERO,
    DEV_RANDOM,
    DEV_TTY,
};

#define SOCK_RX_CAP 16384

struct file {
    enum file_type type;
    int   ref;
    int   readable;
    int   writable;
    int   dev;
    u64   off;
    u32   ino;             /* FD_INODE: ext4 inode number */
    u64   size;            /* FD_INODE: file size */
    int   is_dir;
    char  path[128];       /* absolute path, for *at() dirfd resolution */
    struct ramnode *rnode; /* FD_RAMFS */
    struct pipe   *pipe;   /* FD_PIPE */
    int   sock_domain;
    int   sock_type;
    int   sock_protocol;
    int   sock_bound;
    int   sock_listening;
    int   sock_connected;
    int   sock_shutdown;
    u16   sock_port;
    u16   sock_peer_port;
    struct file *sock_peer;
    struct file *sock_pending;
    u8    sock_rx[SOCK_RX_CAP];
    u32   sock_rx_r;
    u32   sock_rx_len;
};

void          file_init(void);
struct file  *file_alloc(void);
struct file  *file_dup(struct file *f);
void          file_close(struct file *f);
long          file_read(struct file *f, u64 uaddr, u64 n);
long          file_write(struct file *f, u64 uaddr, u64 n);
long          file_read_k(struct file *f, void *kbuf, u64 n);
long          file_pread_k(struct file *f, void *kbuf, u64 off, u64 n);
long          file_write_k(struct file *f, const void *kbuf, u64 n);
long          file_pwrite_k(struct file *f, const void *kbuf, u64 off, u64 n);
int           file_stat(struct file *f, struct kstat *st);
struct file  *console_file(void);
void          socket_unregister_file(struct file *f);
long          socket_deliver_user(struct file *dst, u64 uaddr, u64 n);

/* ramfs: a flat table of created files/dirs keyed by absolute path. */
struct ramnode *ramfs_lookup(const char *path);
struct ramnode *ramfs_create(const char *path, int is_dir);
int            ramfs_unlink(const char *path);
