static int is_dot_entry(const char *name)
{
    return strcmp(name, ".") == 0 || strcmp(name, "..") == 0;
}

static int join_path(char *dst, int max, const char *dir, const char *name)
{
    int n = 0;
    if (max <= 0)
        return -1;
    for (const char *c = dir; *c && n < max - 1; c++)
        dst[n++] = *c;
    if (n == 0) {
        if (n < max - 1)
            dst[n++] = '/';
    } else if (dst[n - 1] != '/') {
        if (n >= max - 1)
            return -1;
        dst[n++] = '/';
    }
    for (const char *c = name; *c && n < max - 1; c++)
        dst[n++] = *c;
    dst[n] = 0;
    return *name == 0 || n >= max - 1 ? -1 : 0;
}

static void parent_dir(const char *path, char *cwd, int max)
{
    int last = -1;
    for (int i = 0; path[i]; i++)
        if (path[i] == '/')
            last = i;
    if (last <= 0) {
        strlcpy(cwd, "/", max);
        return;
    }
    int n = last < max - 1 ? last : max - 1;
    memcpy(cwd, path, (u64)n);
    cwd[n] = 0;
}

static int add_script(struct script_list *list, const char *path)
{
    if (list->count >= MAX_TEST_SCRIPTS)
        return 1;
    struct test_script *s = &list->scripts[list->count++];
    strlcpy(s->path, path, sizeof(s->path));
    parent_dir(path, s->cwd, sizeof(s->cwd));
    return 0;
}

