static int scan_cb(const char *name, u32 ino, u8 type, void *arg)
{
    struct scan_ctx *ctx = arg;
    if (is_dot_entry(name))
        return 0;

    char path[MAX_TEST_PATH];
    if (join_path(path, sizeof(path), ctx->dir, name) < 0)
        return 0;

    if (has_suffix(name, "_testcode.sh"))
        return add_script(ctx->list, path);

    int is_dir = (type == EXT4_FT_DIR) ||
                 (type != EXT4_FT_REG_FILE && ext4_is_dir(ino));
    if (is_dir && ctx->depth < MAX_SCAN_DEPTH)
        return scan_dir(ino, path, ctx->depth + 1, ctx->list);
    return 0;
}

static int scan_dir(u32 dir_ino, const char *dir, int depth,
                    struct script_list *list)
{
    struct scan_ctx ctx = { list, dir, depth };
    return ext4_readdir(dir_ino, scan_cb, &ctx);
}

static int script_phase(const char *path)
{
    if (has_suffix(path, "/basic_testcode.sh"))
        return 0;
    if (has_suffix(path, "/busybox_testcode.sh"))
        return 1;
    if (is_cyclictest_script(path))
        return 2;
    if (is_iozone_script(path))
        return 3;
    if (is_iperf_script(path))
        return 4;
    if (is_netperf_script(path))
        return 5;
    if (is_libcbench_script(path))
        return 6;
    if (is_libctest_script(path))
        return 7;
    if (is_lmbench_script(path))
        return 8;
    if (is_lua_script(path))
        return 9;
    if (is_ltp_script(path))
        return 10;
    return 11;
}

static void sort_scripts(struct script_list *list)
{
    for (int i = 1; i < list->count; i++) {
        for (int j = i; j > 0 &&
             (script_phase(list->scripts[j - 1].path) >
              script_phase(list->scripts[j].path) ||
              (script_phase(list->scripts[j - 1].path) ==
               script_phase(list->scripts[j].path) &&
               strcmp(list->scripts[j - 1].path, list->scripts[j].path) > 0));
             j--) {
            struct test_script tmp;
            memcpy(&tmp, &list->scripts[j - 1], sizeof(tmp));
            memcpy(&list->scripts[j - 1], &list->scripts[j], sizeof(tmp));
            memcpy(&list->scripts[j], &tmp, sizeof(tmp));
        }
    }
}

static void find_busybox_for(const char *cwd, char *out, int max)
{
    if (join_path(out, max, cwd, "busybox") == 0 && ext4_lookup(out))
        return;
    if (ext4_lookup("/busybox")) {
        strlcpy(out, "/busybox", max);
        return;
    }
    strlcpy(out, "/bin/busybox", max);
}

