    struct script_list list;
    list.count = 0;
    scan_dir(EXT4_ROOT_INO, "/", 0, &list);
    sort_scripts(&list);

    char *envp[] = { (char *)"PATH=.:/:/bin:/musl:/glibc", (char *)"HOME=/", NULL };
