            p->xstate = 0;
            p->killed = 0;
            p->entry = NULL;
            p->pagetable = NULL;
            p->trapframe = NULL;
            p->sz = 0;
            p->brk = 0;
            p->mmap_top = USTACK_TOP - (u64)USTACK_PAGES * PGSIZE;
            p->is_thread = 0;
            p->clear_child_tid = 0;
            p->parent = NULL;
            for (int j = 0; j < NOFILE; j++)
                p->ofile[j] = NULL;
            for (int j = 0; j < NVMA; j++) {
