static void proc_release_thread(struct proc *p)
{
    proc_clear_child_tid(p);
    proc_close_files(p);
    proc_free_user_image(p->pagetable, p->sz, p->mmap_top);
    if (p->trapframe)
        kfree_page(p->trapframe);
    p->pagetable = NULL;
    p->trapframe = NULL;
    p->parent = NULL;
    p->state = UNUSED;
}

void proc_free_user_image(pagetable_t pt, u64 sz, u64 mmap_top)
{
    if (!pt)
        return;
    if (mmap_top < USTACK_TOP) {
        u64 start = PGROUNDDOWN(mmap_top);
        uvmunmap(pt, start, (USTACK_TOP - start) / PGSIZE, 1);
    }
    proc_freepagetable(pt, sz);
}

