{
    for (int i = 0; i < NVMA; i++)
        if (p->vmas[i].end && va >= p->vmas[i].start && va < p->vmas[i].end)
            return p->vmas[i].perm;
    return 0;
}

int proc_handle_page_fault(u64 va)
{
    struct proc *p = myproc();
    if (!p || !p->pagetable || va >= MAXVA)
        return -1;
    u64 a = PGROUNDDOWN(va);
    if (uvmcow(p->pagetable, a) == 0)
        return 0;
    if (walkaddr(p->pagetable, a))
        return -1;

    for (int i = 0; i < NPROC; i++) {
        struct proc *q = &proctab[i];
        if (q == p || q->state == UNUSED || !q->pagetable)
            continue;
        if (q->tgid != p->tgid)
            continue;
        if (walkaddr(q->pagetable, a)) {
            if (uvmshare_page(q->pagetable, p->pagetable, a) < 0)
                return -1;
            if (a < p->mmap_top)
                p->mmap_top = a;
            if (q->sz > p->sz)
                p->sz = q->sz;
            return 0;
        }
    }

    u64 stack_low = USTACK_TOP - (u64)USTACK_PAGES * PGSIZE;
    if (a >= stack_low && a < USTACK_TOP &&
        uvmprotect(p->pagetable, a, PGSIZE, PERM_R | PERM_W, 1) == 0)
        return 0;

    int perm = vma_perm_at(p, a);
    if ((perm & (PERM_R | PERM_W | PERM_X)) != 0 &&
        uvmprotect(p->pagetable, a, PGSIZE, perm, 1) == 0) {
        if (a < p->mmap_top)
            p->mmap_top = a;
        return 0;
    }

    for (int i = 0; i < NPROC; i++) {
        struct proc *q = &proctab[i];
        if (q == p || q->state == UNUSED || q->tgid != p->tgid)
            continue;
        if (a < q->sz && uvmprotect(p->pagetable, a, PGSIZE,
                                    PERM_R | PERM_W, 1) == 0) {
            if (q->sz > p->sz)
                p->sz = q->sz;
            return 0;
        }
    }

    return -1;
}

