    u64 e_entry = rd64(elf + 24);
    u64 e_phoff = rd64(elf + 32);
    u16 e_phentsize = rd16(elf + 54);
    u16 e_phnum = rd16(elf + 56);

    u64 bias = (e_type == ET_DYN) ? dyn_base : 0;
    u64 sz = 0;
    u64 phdr_va = 0;
    u64 first_load_va = 0, first_load_off = 0;
    int have_first = 0;

    for (u16 i = 0; i < e_phnum; i++) {
        const u8 *ph = elf + e_phoff + (u64)i * e_phentsize;
        if ((u64)(ph - elf) + 56 > elflen)
            return -1;
        u32 type = rd32(ph + 0);

        if (type == PT_INTERP) {
            u64 off = rd64(ph + 8);
            u64 filesz = rd64(ph + 32);
            if (filesz == 0 || off + filesz > elflen)
                return -1;
            u64 n = filesz < sizeof(info->interp) - 1 ?
                    filesz : sizeof(info->interp) - 1;
            memcpy(info->interp, elf + off, n);
            info->interp[n] = 0;
            continue;
        }

        if (type == PT_PHDR)
            phdr_va = rd64(ph + 16) + bias;
        if (type != PT_LOAD)
            continue;

        u32 flags = rd32(ph + 4);
        u64 off = rd64(ph + 8);
        u64 vaddr = rd64(ph + 16) + bias;
        u64 filesz = rd64(ph + 32);
        u64 memsz = rd64(ph + 40);

        if (memsz < filesz || off + filesz > elflen)
            return -1;
        if (!have_first) {
            first_load_va = vaddr;
            first_load_off = off;
            have_first = 1;
        }

        int perm = PERM_U | PERM_R;
        if (flags & PF_W)
            perm |= PERM_W;
        if (flags & PF_X)
            perm |= PERM_X;

        u64 va_end = vaddr + memsz;
        for (u64 a = PGROUNDDOWN(vaddr); a < va_end; a += PGSIZE) {
            if (walkaddr(pt, a) != 0)
                continue;
            void *mem = kalloc_page();
            if (!mem)
                return -1;
            if (mappages(pt, a, PGSIZE, (u64)mem, perm) < 0) {
                kfree_page(mem);
                return -1;
            }
        }
        if (filesz > 0 && copyout(pt, vaddr, elf + off, filesz) < 0)
            return -1;
        if (va_end > sz)
            sz = va_end;
    }

    if (phdr_va == 0 && have_first)
        phdr_va = first_load_va + (e_phoff - first_load_off);

    info->entry = e_entry + bias;
    info->aux_entry = info->entry;
    info->base = bias;
    info->sz = sz;
    info->phdr = phdr_va;
    info->phnum = e_phnum;
    info->phent = e_phentsize;
    return 0;
}

