static const char *path_group(const char *path)
{
    if (strncmp(path, "/glibc/", 7) == 0 || strcmp(path, "/glibc") == 0)
        return "glibc";
    if (strncmp(path, "/musl/", 6) == 0 || strcmp(path, "/musl") == 0)
        return "musl";
    return NULL;
}

static int join_path(char *dst, int max, const char *dir, const char *name)
{
    int n = 0;
    if (max <= 0)
        return -1;
    for (const char *c = dir; *c && n < max - 1; c++)
        dst[n++] = *c;
    if (n == 0) {
        if (n < max - 1)
            dst[n++] = '/';
    } else if (dst[n - 1] != '/') {
        if (n >= max - 1)
            return -1;
        dst[n++] = '/';
    }
    for (const char *c = name; *c && n < max - 1; c++)
        dst[n++] = *c;
    dst[n] = 0;
    return *name == 0 || n >= max - 1 ? -1 : 0;
}

static int join3(char *dst, int max, const char *a, const char *b,
                 const char *c)
{
    if (max <= 0)
        return -1;
    int n = 0;
    for (const char *p = a; *p && n < max - 1; p++)
        dst[n++] = *p;
    for (const char *p = b; *p && n < max - 1; p++)
        dst[n++] = *p;
    for (const char *p = c; *p && n < max - 1; p++)
        dst[n++] = *p;
    dst[n] = 0;
    return n >= max - 1 ? -1 : 0;
}

static int find_group_lib(char *out, int max, const char *group,
                          const char *dir, const char *name)
{
    if (join3(out, max, "/", group, dir) < 0)
        return -1;
    u64 n = strlen(out);
    strlcpy(out + n, name, max - (int)n);
    return ext4_lookup(out) ? 0 : -1;
}

static void parent_dir(const char *path, char *out, int max)
{
    int last = -1;
    for (int i = 0; path[i]; i++)
        if (path[i] == '/')
            last = i;
    if (last <= 0) {
        strlcpy(out, "/", max);
        return;
    }
    int n = last < max - 1 ? last : max - 1;
    for (int i = 0; i < n; i++)
        out[i] = path[i];
    out[n] = 0;
}

static int find_nearby_busybox(const char *script, char *out, int max)
{
    char dir[128];
    parent_dir(script, dir, sizeof(dir));
    for (int depth = 0; depth < 6; depth++) {
        if (join_path(out, max, dir, "busybox") == 0 && ext4_lookup(out))
            return 0;
        if (strcmp(dir, "/") == 0)
            break;
        char up[128];
        parent_dir(dir, up, sizeof(up));
        strlcpy(dir, up, sizeof(dir));
    }
    if (ext4_lookup("/busybox")) {
        strlcpy(out, "/busybox", max);
        return 0;
    }
    if (ext4_lookup("/bin/busybox")) {
        strlcpy(out, "/bin/busybox", max);
        return 0;
    }
    if (ext4_lookup("/musl/busybox")) {
        strlcpy(out, "/musl/busybox", max);
        return 0;
    }
    if (ext4_lookup("/glibc/busybox")) {
        strlcpy(out, "/glibc/busybox", max);
        return 0;
    }
    return -ENOENT;
}

static int find_exec_busybox(struct proc *p, const char *path, char *out, int max)
{
    if (find_nearby_busybox(path, out, max) == 0)
        return 0;
    if (p && join_path(out, max, p->cwd, "busybox") == 0 && ext4_lookup(out))
        return 0;
    if (ext4_lookup("/busybox")) {
        strlcpy(out, "/busybox", max);
        return 0;
    }
    if (ext4_lookup("/bin/busybox")) {
        strlcpy(out, "/bin/busybox", max);
        return 0;
    }
    if (ext4_lookup("/musl/busybox")) {
        strlcpy(out, "/musl/busybox", max);
        return 0;
    }
    if (ext4_lookup("/glibc/busybox")) {
        strlcpy(out, "/glibc/busybox", max);
        return 0;
    }
    return -ENOENT;
}

static int is_shebang_script(const u8 *buf, long n)
{
    return n >= 2 && buf[0] == '#' && buf[1] == '!';
}

static const char *basename(const char *path)
{
    const char *base = path;
    for (const char *c = path; *c; c++)
        if (*c == '/')
            base = c + 1;
    return base;
}

static int resolve_interp(const char *prog, const char *cwd,
                          const char *interp, char *out, int max)
{
    if (ext4_lookup(interp)) {
        strlcpy(out, interp, max);
        return 0;
    }

    const char *group = path_group(prog);
    if (!group)
        group = path_group(cwd && cwd[0] ? cwd : "/");
    if (group) {
        const char *name = NULL;
        int prefer64 = 0;
        if (strncmp(interp, "/lib/", 5) == 0) {
            name = interp + 5;
        } else if (strncmp(interp, "/lib64/", 7) == 0) {
            name = interp + 7;
            prefer64 = 1;
        }
        if (name) {
            if (prefer64 && find_group_lib(out, max, group, "/lib64/", name) == 0)
                return 0;
            if (find_group_lib(out, max, group, "/lib/", name) == 0)
                return 0;
            if (!prefer64 && find_group_lib(out, max, group, "/lib64/", name) == 0)
                return 0;
        }
        if (strcmp(group, "musl") == 0 &&
            join3(out, max, "/", group, "/lib/libc.so") == 0 &&
            ext4_lookup(out))
            return 0;
    }
    return -ENOENT;
}

