static u64 build_stack(pagetable_t pt, const struct elf_info *info,
                       char *const argv[], char *const envp[])
{
    u64 sp = USTACK_TOP;
    u64 uargv[64], uenvp[64];
    int argc = 0, envc = 0;

    for (; argv && argv[argc] && argc < 63; argc++) {
        u64 len = strlen(argv[argc]) + 1;
        sp -= len;
        if (copyout(pt, sp, argv[argc], len) < 0)
            return 0;
        uargv[argc] = sp;
    }
    for (; envp && envp[envc] && envc < 63; envc++) {
        u64 len = strlen(envp[envc]) + 1;
        sp -= len;
        if (copyout(pt, sp, envp[envc], len) < 0)
            return 0;
        uenvp[envc] = sp;
    }

    u8 rnd[16];
    for (int i = 0; i < 16; i++)
        rnd[i] = (u8)(0x5a ^ (i * 7 + 3));
    sp -= 16;
    sp &= ~0xfUL;
    u64 at_random = sp;
    if (copyout(pt, sp, rnd, 16) < 0)
        return 0;

    u64 aux[][2] = {
        { AT_PHDR, info->phdr }, { AT_PHENT, info->phent },
        { AT_PHNUM, info->phnum }, { AT_PAGESZ, PGSIZE },
        { AT_BASE, info->at_base }, { AT_FLAGS, 0 },
        { AT_ENTRY, info->aux_entry },
        { AT_UID, 0 }, { AT_EUID, 0 }, { AT_GID, 0 }, { AT_EGID, 0 },
        { AT_HWCAP, 0 }, { AT_CLKTCK, 100 }, { AT_SECURE, 0 },
        { AT_RANDOM, at_random }, { AT_NULL, 0 },
    };
    int naux = (int)(sizeof(aux) / sizeof(aux[0]));

    u64 nptr = 1 + (u64)(argc + 1) + (u64)(envc + 1) + (u64)naux * 2;
    sp -= nptr * 8;
    sp &= ~0xfUL;

    u64 stackbuf[1 + 64 + 1 + 64 + 1 + 2 * 16];
    int k = 0;
    stackbuf[k++] = (u64)argc;
    for (int i = 0; i < argc; i++)
        stackbuf[k++] = uargv[i];
    stackbuf[k++] = 0;
    for (int i = 0; i < envc; i++)
        stackbuf[k++] = uenvp[i];
    stackbuf[k++] = 0;
    for (int i = 0; i < naux; i++) {
        stackbuf[k++] = aux[i][0];
        stackbuf[k++] = aux[i][1];
    }
    if (copyout(pt, sp, stackbuf, (u64)k * 8) < 0)
        return 0;
    return sp;
}

/* Build a fresh image for p (which already has a trapframe). On success sets
 * p->pagetable/sz/brk and the trapframe entry/sp, returning the previous page
 * table + size via old_pt/old_sz so the caller can free them. */
static int setup_image_depth(struct proc *p, const char *path,
                             char *const argv[], char *const envp[],
                             pagetable_t *old_pt, u64 *old_sz, int depth)
{
    u32 ino = ext4_lookup(path);
    struct ramnode *rn = ramfs_lookup(path);
    const char *app = basename(path);
    if (!ino && (!rn || rn->is_dir ||
                 (rn->size == 0 && is_busybox_applet(app)))) {
        if (depth < 4 && is_busybox_applet(app)) {
            char busybox[160];
            if (find_exec_busybox(p, path, busybox, sizeof(busybox)) == 0) {
                char *bb_argv[20];
                int k = 0;
                bb_argv[k++] = (char *)app;
                for (int i = 1; argv && argv[i] && k < 19; i++)
                    bb_argv[k++] = argv[i];
                bb_argv[k] = NULL;
                return setup_image_depth(p, busybox, bb_argv, envp, old_pt,
                                         old_sz, depth + 1);
            }
        }
        return -ENOENT;
    }
    long n;
    if (rn && !rn->is_dir) {
        if (rn->size > sizeof(elf_buf))
            return -ENOEXEC;
        if (rn->size) {
            struct file rf;
            memset(&rf, 0, sizeof(rf));
            rf.type = FD_RAMFS;
            rf.readable = 1;
            rf.rnode = rn;
            n = file_pread_k(&rf, elf_buf, 0, rn->size);
            if (n != (long)rn->size)
                return -ENOEXEC;
        } else {
            n = 0;
        }
    } else {
        n = ext4_read(ino, elf_buf, sizeof(elf_buf), NULL);
    }
    if (n <= 0)
        return -ENOEXEC;

    if (is_shebang_script(elf_buf, n)) {
        if (depth >= 4)
            return -ENOEXEC;
        char busybox[160];
        if (find_nearby_busybox(path, busybox, sizeof(busybox)) < 0)
            return -ENOENT;

        char *sh_argv[20];
        int k = 0;
        sh_argv[k++] = (char *)"busybox";
        sh_argv[k++] = (char *)"sh";
        sh_argv[k++] = (char *)path;
        for (int i = 1; argv && argv[i] && k < 19; i++)
            sh_argv[k++] = argv[i];
        sh_argv[k] = NULL;
        return setup_image_depth(p, busybox, sh_argv, envp, old_pt, old_sz,
                                 depth + 1);
    }

    pagetable_t newpt = proc_pagetable(p);
    if (!newpt)
        return -ENOMEM;

    struct elf_info info;
    if (elf_load(newpt, elf_buf, (u64)n, ELF_MAIN_BASE, &info) < 0) {
        proc_freepagetable(newpt, 0);
        return -ENOEXEC;
    }
    u64 runtime_entry = info.entry;

    if (info.interp[0]) {
        char ipath[160];
        if (resolve_interp(path, p->cwd, info.interp, ipath, sizeof(ipath)) < 0) {
            proc_freepagetable(newpt, info.sz);
            return -ENOENT;
        }
        u32 iino = ext4_lookup(ipath);
        long in = ext4_read(iino, elf_buf, sizeof(elf_buf), NULL);
        if (in <= 0) {
            proc_freepagetable(newpt, info.sz);
            return -ENOEXEC;
        }
        struct elf_info interp;
        if (elf_load(newpt, elf_buf, (u64)in, ELF_INTERP_BASE, &interp) < 0) {
            proc_freepagetable(newpt, info.sz);
            return -ENOEXEC;
        }
        if (interp.sz > info.sz)
            info.sz = interp.sz;
        info.at_base = interp.base;
        runtime_entry = interp.entry;
    }

    u64 stk_base = USTACK_TOP - (u64)USTACK_PAGES * PGSIZE;
    u64 stk_map = USTACK_TOP - (u64)USTACK_INITIAL_PAGES * PGSIZE;
    for (u64 a = stk_map; a < USTACK_TOP; a += PGSIZE) {
        void *m = kalloc_page();
        if (!m) {
            proc_freepagetable(newpt, info.sz);
            return -ENOMEM;
        }
        mappages(newpt, a, PGSIZE, (u64)m, PERM_R | PERM_W | PERM_U);
    }

    u64 sp = build_stack(newpt, &info, argv, envp);
    if (sp == 0) {
        proc_freepagetable(newpt, info.sz);
        return -EFAULT;
    }

    *old_pt = p->pagetable;
    *old_sz = p->sz;
    p->pagetable = newpt;
    p->sz = info.sz;
    p->brk = PGROUNDUP(info.sz);
    p->mmap_top = stk_base;
    for (int i = 0; i < NVMA; i++) {
        p->vmas[i].start = 0;
        p->vmas[i].end = 0;
        p->vmas[i].shared = 0;
        p->vmas[i].perm = 0;
        p->vmas[i].shmid = 0;
    }

    memset(p->trapframe, 0, sizeof(*p->trapframe));
    p->trapframe->epc = runtime_entry;
    p->trapframe->sp = sp;
    return 0;
}

