int exec_user_cwd(const char *path, char *const argv[], char *const envp[],
                  const char *cwd)
{
    struct proc *p = proc_alloc();
    if (!p)
        return -1;
    p->trapframe = (struct trapframe *)kalloc_page();
    if (!p->trapframe) {
        p->state = UNUSED;
        return -1;
    }
    /* stdin/stdout/stderr on the console */
    p->ofile[0] = console_file();
    p->ofile[1] = console_file();
    p->ofile[2] = console_file();

    pagetable_t old_pt = NULL;
    u64 old_sz = 0;
    int rc = setup_image(p, path, argv, envp, &old_pt, &old_sz);
    if (rc < 0) {
        kfree_page(p->trapframe);
        p->state = UNUSED;
        printk("[exec] failed to load %s\n", path);
        return rc;
    }

    p->ctx.ra = (u64)forkret;
    p->ctx.sp = p->kstack + KSTACK_SIZE;
    strlcpy(p->name, path, sizeof(p->name));
    strlcpy(p->cwd, cwd && cwd[0] ? cwd : "/", sizeof(p->cwd));
    p->state = RUNNABLE;
    return 0;
}

int exec_user(const char *path, char *const argv[], char *const envp[])
{
    return exec_user_cwd(path, argv, envp, "/");
}

/* Replace the current process image (execve). Does not return on success. */
int exec_replace(const char *path, char *const argv[], char *const envp[])
{
    struct proc *p = myproc();
    pagetable_t prev_pt = p->pagetable;
    u64 prev_sz = p->sz;
    u64 prev_mmap_top = p->mmap_top;
    pagetable_t old_pt = NULL;
    u64 old_sz = 0;
    int was = arch_intr_get();
    arch_intr_off();
    int rc = setup_image(p, path, argv, envp, &old_pt, &old_sz);
    if (rc < 0) {
        if (was)
            arch_intr_on();
        return rc;
    }
    if (old_pt)
        proc_free_user_image(prev_pt, prev_sz, prev_mmap_top);
    strlcpy(p->name, path, sizeof(p->name));
    if (was)
        arch_intr_on();
    return 0;
}

