static long copy_single_node_mask(struct proc *p, u64 unodemask, u64 maxnode)
{
    if (!unodemask)
        return 0;
    if (maxnode == 0)
        return -EINVAL;

    u64 words = (maxnode + 63) / 64;
    u64 one = 1;
    u64 zero = 0;
    if (copyout(p->pagetable, unodemask, &one, sizeof(one)) < 0)
        return -EFAULT;
    for (u64 i = 1; i < words; i++) {
        if (copyout(p->pagetable, unodemask + i * sizeof(u64),
                    &zero, sizeof(zero)) < 0)
            return -EFAULT;
    }
    return 0;
}

