    u64 unodemask = p->trapframe->a1;
    u64 maxnode = p->trapframe->a2;
    u64 flags = p->trapframe->a4;

    if (flags & ~(u64)(MPOL_F_NODE | MPOL_F_ADDR))
        return -EINVAL;

    int mode = (flags & MPOL_F_NODE) ? 0 : MPOL_DEFAULT;
    if (umode && copyout(p->pagetable, umode, &mode, sizeof(mode)) < 0)
        return -EFAULT;
    return copy_single_node_mask(p, unodemask, maxnode);
}

