static void fill_rlimit(int resource, u64 *cur, u64 *max)
{
    *cur = 64UL * 1024 * 1024;
    *max = 64UL * 1024 * 1024;
    if (resource == 7) {
        *cur = NOFILE;
        *max = NOFILE;
    } else if (resource == 3) {
        *cur = 256UL * 1024;
        *max = 256UL * 1024;
    } else if (resource == 4) {
        *cur = 0;
        *max = 0;
    }
}

