static u16 sockaddr_port(struct proc *p, u64 uaddr, u64 len)
{
    if (!uaddr || len < 4)
        return 0;
    struct sockaddr_any sa;
    memset(&sa, 0, sizeof(sa));
    u64 n = len < sizeof(sa) ? len : sizeof(sa);
    if (copyin(p->pagetable, &sa, uaddr, n) < 0)
        return 0;
    if (sa.family != AF_INET && sa.family != AF_INET6)
        return 0;
    return bswap16(sa.port_be);
}

static int copy_sockaddr(struct proc *p, u64 uaddr, u64 ulenaddr, u16 port)
{
    if (!uaddr)
        return 0;
    u32 len = 16;
    if (ulenaddr && copyin(p->pagetable, &len, ulenaddr, sizeof(len)) < 0)
        return -EFAULT;
    struct sockaddr_any sa;
    memset(&sa, 0, sizeof(sa));
    sa.family = AF_INET;
    sa.port_be = bswap16(port);
    sa.rest[2] = 127;
    sa.rest[5] = 1;
    u64 n = len < 16 ? len : 16;
    if (copyout(p->pagetable, uaddr, &sa, n) < 0)
        return -EFAULT;
    if (ulenaddr) {
        u32 outlen = 16;
        if (copyout(p->pagetable, ulenaddr, &outlen, sizeof(outlen)) < 0)
            return -EFAULT;
    }
    return 0;
}

static void socket_unregister(struct file *f)
{
    for (int i = 0; i < NSOCKREG; i++) {
        if (socktab[i].used && socktab[i].f == f) {
            socktab[i].used = 0;
            socktab[i].f = NULL;
        }
    }
}

static struct file *find_bound_socket(u16 port, int type, int listening)
{
    for (int i = 0; i < NSOCKREG; i++) {
        struct file *f = socktab[i].f;
        if (!socktab[i].used)
            continue;
        if (!f || f->type != FD_SOCKET || f->ref <= 0) {
            socktab[i].used = 0;
            socktab[i].f = NULL;
            continue;
        }
        if (socktab[i].port == port && socktab[i].type == type &&
            (!listening || f->sock_listening))
            return f;
    }
    return NULL;
}

static int socket_register(struct file *f)
{
    if (f->sock_port && find_bound_socket(f->sock_port, f->sock_type, 0))
        return -EADDRINUSE;
    for (int i = 0; i < NSOCKREG; i++) {
        if (!socktab[i].used) {
            socktab[i].used = 1;
            socktab[i].port = f->sock_port;
            socktab[i].type = f->sock_type;
            socktab[i].f = f;
            return 0;
        }
    }
    return -ENOSPC;
}

static u16 next_ephemeral_port = 49152;

static int socket_bind_ephemeral(struct file *f)
{
    if (f->sock_bound)
        return 0;
    for (int i = 0; i < 16384; i++) {
        u16 port = next_ephemeral_port++;
        if (next_ephemeral_port < 49152)
            next_ephemeral_port = 49152;
        if (find_bound_socket(port, f->sock_type, 0))
            continue;
        f->sock_port = port;
        f->sock_bound = 1;
        int rc = socket_register(f);
        if (rc < 0) {
            f->sock_bound = 0;
            f->sock_port = 0;
            return rc;
        }
        return 0;
    }
    return -EADDRINUSE;
}

