static int dev_kind(const char *path)
{
    if (strcmp(path, "/dev/null") == 0)
        return DEV_NULL;
    if (strcmp(path, "/dev/zero") == 0)
        return DEV_ZERO;
    if (strcmp(path, "/dev/random") == 0 || strcmp(path, "/dev/urandom") == 0)
        return DEV_RANDOM;
    if (strcmp(path, "/dev/tty") == 0 || strcmp(path, "/dev/console") == 0)
        return DEV_TTY;
    return -1;
}

static const char *path_group(const char *path)
{
    if (strncmp(path, "/glibc/", 7) == 0 || strcmp(path, "/glibc") == 0)
        return "glibc";
    if (strncmp(path, "/musl/", 6) == 0 || strcmp(path, "/musl") == 0)
        return "musl";
    return NULL;
}

static int try_alias_file(char *abs, int max, const char *group,
                          const char *dir, const char *name)
{
    char alias[160];
    int n = 0;
    if (n < (int)sizeof(alias) - 1)
        alias[n++] = '/';
    for (const char *c = group; *c && n < (int)sizeof(alias) - 1; c++)
        alias[n++] = *c;
    for (const char *c = dir; *c && n < (int)sizeof(alias) - 1; c++)
        alias[n++] = *c;
    for (const char *c = name; *c && n < (int)sizeof(alias) - 1; c++)
        alias[n++] = *c;
    alias[n] = 0;
    if (ramfs_lookup(alias) || ext4_lookup(alias)) {
        strlcpy(abs, alias, max);
        return 1;
    }
    return 0;
}

static void maybe_alias_lib_path(struct proc *p, char *abs, int max)
{
    if (ramfs_lookup(abs) || ext4_lookup(abs))
        return;

    const char *group = path_group(p->cwd);
    if (!group) {
        group = path_group(abs);
        if (!group)
            return;
    }

    const char *name = NULL;
    int prefer64 = 0;
    if (strncmp(abs, "/lib/", 5) == 0) {
        name = abs + 5;
    } else if (strncmp(abs, "/lib64/", 7) == 0) {
        name = abs + 7;
        prefer64 = 1;
    } else {
        u64 glen = strlen(group);
        if (abs[0] == '/' && strncmp(abs + 1, group, glen) == 0 &&
            abs[glen + 1] == '/' && abs[glen + 2] != '\0') {
            const char *rel = abs + glen + 2;
            int nested = 0;
            for (const char *c = rel; *c; c++)
                if (*c == '/')
                    nested = 1;
            if (!nested)
                name = rel;
        }
    }
    if (!name)
        return;

    if (prefer64 && try_alias_file(abs, max, group, "/lib64/", name))
        return;
    if (try_alias_file(abs, max, group, "/lib/", name))
        return;
    if (!prefer64 && try_alias_file(abs, max, group, "/lib64/", name))
        return;

    if (strcmp(group, "glibc") == 0) {
        if (strcmp(name, "libc.so.6") == 0 &&
            (try_alias_file(abs, max, "glibc", "/lib64/", "libc.so") ||
             try_alias_file(abs, max, "glibc", "/lib/", "libc.so")))
            return;
        if (strcmp(name, "libm.so.6") == 0 &&
            (try_alias_file(abs, max, "glibc", "/lib64/", "libm.so") ||
             try_alias_file(abs, max, "glibc", "/lib/", "libm.so")))
            return;
    }
    if (strcmp(group, "musl") == 0) {
        try_alias_file(abs, max, "musl", "/lib/", "libc.so");
    }
}

