static struct file *getf(struct proc *p, int fd)
{
    if (fd < 0 || fd >= NOFILE)
        return NULL;
    return p->ofile[fd];
}

static int fd_alloc(struct proc *p, struct file *f)
{
    for (int i = 0; i < NOFILE; i++) {
        if (!p->ofile[i]) {
            p->ofile[i] = f;
            return i;
        }
    }
    return -1;
}

long sys_openat(struct proc *p)
{
    u64 upath = p->trapframe->a1;
    int flags = (int)p->trapframe->a2;
    char path[128], abs[160];
    if (fetch_str(p, upath, path, sizeof(path)) < 0)
        return -EFAULT;
    long rr = resolve_at(p, (int)p->trapframe->a0, path, abs, sizeof(abs));
    if (rr < 0)
        return rr;
    if ((flags & O_NOATIME) && p->euid != 0)
        return -EPERM;

    struct file *f = file_alloc();
    if (!f)
        return -EMFILE;
    int acc = flags & O_ACCMODE;
    f->readable = (acc == O_RDONLY || acc == O_RDWR);
    f->writable = (acc == O_WRONLY || acc == O_RDWR);
    f->off = 0;
    strlcpy(f->path, abs, sizeof(f->path));

    int dev = dev_kind(abs);
    if (dev >= 0) {
        f->type = FD_DEVICE;
        f->dev = dev;
        f->readable = (dev != DEV_NULL);
        f->writable = 1;
    } else {
        struct ramnode *rn = ramfs_lookup(abs);
        if (rn) {
            if ((flags & O_CREAT) && (flags & O_EXCL)) {
                file_close(f);
                return -EEXIST;
            }
            f->type = FD_RAMFS;
            f->rnode = rn;
            if ((flags & O_TRUNC) && ramfs_resize(rn, 0, 0) < 0) {
                file_close(f);
                return -EIO;
            }
        } else {
            u32 ino = ext4_lookup(abs);
            if (ino) {
                if ((flags & O_CREAT) && (flags & O_EXCL)) {
                    file_close(f);
                    return -EEXIST;
                }
                f->type = FD_INODE;
                f->ino = ino;
                f->size = ext4_size(ino);
                f->is_dir = ext4_is_dir(ino);
            } else if (flags & O_CREAT) {
                rn = ramfs_create(abs, 0);
                if (!rn) {
                    file_close(f);
                    return -ENOSPC;
                }
                rn->mode = S_IFREG | (u16)(p->trapframe->a3 & ~p->umask & 07777);
                f->type = FD_RAMFS;
                f->rnode = rn;
            } else {
                file_close(f);
                return -ENOENT;
            }
        }
    }
    if (flags & O_APPEND) {
        if (f->type == FD_RAMFS && f->rnode)
            f->off = f->rnode->size;
        else if (f->type == FD_INODE)
            f->off = f->size;
    }
    int fd = fd_alloc(p, f);
    if (fd < 0) {
        file_close(f);
        return -EMFILE;
    }
    return fd;
}

