static void put32(u8 *b, u32 v) { memcpy(b, &v, 4); }
static void put64(u8 *b, u64 v) { memcpy(b, &v, 8); }
static void put16(u8 *b, u16 v) { memcpy(b, &v, 2); }

#define STATX_BASIC_STATS 0x000007ffU
#define AT_EMPTY_PATH 0x1000

long sys_statx(struct proc *p)
{
    int dirfd = (int)p->trapframe->a0;
    u64 upath = p->trapframe->a1;
    int flags = (int)p->trapframe->a2;
    u64 ubuf = p->trapframe->a4;

    char path[128], abs[160];
    if (fetch_str(p, upath, path, sizeof(path)) < 0)
        return -EFAULT;

    u16 mode = 0;
    u64 ino = 0, size = 0;

    if (path[0] == '\0' && (flags & AT_EMPTY_PATH)) {
        struct file *f = getf(p, dirfd);
        if (!f)
            return -EBADF;
        struct kstat ks;
        if (file_stat(f, &ks) < 0)
            return -EINVAL;
        mode = (u16)ks.st_mode;
        ino = ks.st_ino;
        size = (u64)ks.st_size;
    } else {
        long rr = resolve_at(p, dirfd, path, abs, sizeof(abs));
        if (rr < 0)
            return rr;
        struct ramnode *rn = ramfs_lookup(abs);
        if (rn) {
            mode = rn->mode;
            size = rn->size;
        } else {
            u32 i = ext4_lookup(abs);
            if (!i)
                return -ENOENT;
            ino = i;
            size = ext4_size(i);
            mode = (ext4_is_dir(i) ? S_IFDIR : S_IFREG) | 0755;
        }
    }

    u8 sx[256];
    memset(sx, 0, sizeof(sx));
    put32(sx + 0, STATX_BASIC_STATS);   /* stx_mask */
    put32(sx + 4, 512);                 /* stx_blksize */
    put32(sx + 16, 1);                  /* stx_nlink */
    put16(sx + 28, mode);               /* stx_mode */
    put64(sx + 32, ino);                /* stx_ino */
    put64(sx + 40, size);               /* stx_size */
    put64(sx + 48, (size + 511) / 512); /* stx_blocks */
    if (copyout(p->pagetable, ubuf, sx, sizeof(sx)) < 0)
        return -EFAULT;
    return 0;
}

/* ---- getdents64 ---- */

struct dents_ctx {
    struct proc *p;
    u64  ubuf;
    u64  cap;
    u64  written;
    u64  skip;       /* entries already returned in previous calls */
    u64  seen;
    int  err;
};

static int dents_cb(const char *name, u32 ino, u8 type, void *arg)
{
    struct dents_ctx *c = arg;
    if (c->seen++ < c->skip)
        return 0;
    u64 namelen = strlen(name);
    u64 reclen = (19 + namelen + 1 + 7) & ~7UL;   /* align 8 */
    if (c->written + reclen > c->cap)
        return 1;   /* buffer full: stop */
    u8 rec[320];
    memset(rec, 0, reclen);
    u64 d_ino = ino;
    i64 d_off = (i64)(c->seen);
    u16 d_reclen = (u16)reclen;
    memcpy(rec + 0, &d_ino, 8);
    memcpy(rec + 8, &d_off, 8);
    memcpy(rec + 16, &d_reclen, 2);
    rec[18] = type;
    memcpy(rec + 19, name, namelen + 1);
    if (copyout(c->p->pagetable, c->ubuf + c->written, rec, reclen) < 0) {
        c->err = 1;
        return 1;
    }
    c->written += reclen;
    return 0;
}

long sys_getdents64(struct proc *p)
{
    struct file *f = getf(p, (int)p->trapframe->a0);
    if (!f)
        return -EBADF;
    if (f->type != FD_INODE && f->type != FD_RAMFS)
        return -ENOTDIR;
    if (f->type == FD_INODE && !f->is_dir)
        return -ENOTDIR;
    if (f->type == FD_RAMFS && (!f->rnode || !f->rnode->is_dir))
        return -ENOTDIR;
    struct dents_ctx c;
    memset(&c, 0, sizeof(c));
    c.p = p;
    c.ubuf = p->trapframe->a1;
    c.cap = p->trapframe->a2;
    if (f->type == FD_INODE) {
        u64 off = f->off;
        ext4_readdir_from(f->ino, &off, dents_cb, &c);
        f->off = off;
    } else {
        c.skip = f->off;
        ramfs_readdir(f->rnode, dents_cb, &c);
        f->off = c.seen;          /* advance past what we returned */
    }
    if (c.err)
        return -EFAULT;
    return (long)c.written;
}

long sys_pipe2(struct proc *p)
{
    struct file *rf, *wf;
    if (pipe_alloc(&rf, &wf) < 0)
        return -ENOMEM;
    int fd0 = fd_alloc(p, rf);
    int fd1 = fd_alloc(p, wf);
    if (fd0 < 0 || fd1 < 0) {
        if (fd0 >= 0) p->ofile[fd0] = NULL;
        file_close(rf);
        file_close(wf);
        return -EMFILE;
    }
    int fds[2] = { fd0, fd1 };
    if (copyout(p->pagetable, p->trapframe->a0, fds, sizeof(fds)) < 0)
        return -EFAULT;
    return 0;
}

long sys_getcwd(struct proc *p)
{
    u64 ubuf = p->trapframe->a0;
    u64 size = p->trapframe->a1;
    u64 n = strlen(p->cwd) + 1;
    if (n > size)
        return -ERANGE;
    if (copyout(p->pagetable, ubuf, p->cwd, n) < 0)
        return -EFAULT;
    return (long)ubuf;
}

long sys_chdir(struct proc *p)
{
    char path[128], abs[160];
    if (fetch_str(p, p->trapframe->a0, path, sizeof(path)) < 0)
        return -EFAULT;
    long rr = resolve(p, path, abs, sizeof(abs));
    if (rr < 0)
        return rr;
    struct ramnode *rn = ramfs_lookup(abs);
    if (rn) {
        if (!rn->is_dir)
            return -ENOTDIR;
    } else {
        u32 ino = ext4_lookup(abs);
        if (!ino)
            return -ENOENT;
        if (!ext4_is_dir(ino))
            return -ENOTDIR;
    }
    strlcpy(p->cwd, abs, sizeof(p->cwd));
    return 0;
}

