long sys_bind(struct proc *p)
{
    struct file *f = getf(p, (int)p->trapframe->a0);
    if (!f || f->type != FD_SOCKET)
        return -EBADF;
    u16 port = sockaddr_port(p, p->trapframe->a1, p->trapframe->a2);
    if (port == 0)
        port = next_ephemeral_port++;
    socket_unregister(f);
    f->sock_port = port;
    f->sock_bound = 1;
    int rc = socket_register(f);
    if (rc < 0) {
        f->sock_bound = 0;
        f->sock_port = 0;
        return rc;
    }
    return 0;
}

long sys_listen(struct proc *p)
{
    struct file *f = getf(p, (int)p->trapframe->a0);
    if (!f || f->type != FD_SOCKET)
        return -EBADF;
    if (f->sock_type != SOCK_STREAM)
        return -EOPNOTSUPP;
    int rc = socket_bind_ephemeral(f);
    if (rc < 0)
        return rc;
    f->sock_listening = 1;
    return 0;
}

long sys_connect(struct proc *p)
{
    struct file *f = getf(p, (int)p->trapframe->a0);
    if (!f || f->type != FD_SOCKET)
        return -EBADF;
    u16 port = sockaddr_port(p, p->trapframe->a1, p->trapframe->a2);
    if (port == 0)
        return -EINVAL;
    int rc = socket_bind_ephemeral(f);
    if (rc < 0)
        return rc;
    f->sock_peer_port = port;
    if (f->sock_type == SOCK_DGRAM) {
        f->sock_connected = 1;
        return 0;
    }

    struct file *listener = find_bound_socket(port, SOCK_STREAM, 1);
    if (!listener)
        return -ECONNREFUSED;
    struct file *srv = file_alloc();
    if (!srv)
        return -EMFILE;
    srv->type = FD_SOCKET;
    srv->readable = 1;
    srv->writable = 1;
    srv->sock_domain = listener->sock_domain;
    srv->sock_type = SOCK_STREAM;
    srv->sock_protocol = listener->sock_protocol;
    srv->sock_bound = 1;
    srv->sock_connected = 1;
    srv->sock_port = listener->sock_port;
    srv->sock_peer_port = f->sock_port;
    socket_reset_rx(srv);
    socket_reset_rx(f);
    srv->sock_peer = f;
    f->sock_peer = srv;
    f->sock_connected = 1;
    if (listener->sock_pending)
        file_close(listener->sock_pending);
    listener->sock_pending = srv;
    return 0;
}

long sys_accept(struct proc *p)
{
    struct file *listener = getf(p, (int)p->trapframe->a0);
    if (!listener || listener->type != FD_SOCKET)
        return -EBADF;
    if (!listener->sock_listening || listener->sock_type != SOCK_STREAM)
        return -EINVAL;
    if (!listener->sock_pending)
        return -EAGAIN;
    struct file *srv = listener->sock_pending;
    listener->sock_pending = NULL;
    int fd = fd_alloc(p, srv);
    if (fd < 0) {
        file_close(srv);
        return -EMFILE;
    }
    copy_sockaddr(p, p->trapframe->a1, p->trapframe->a2, srv->sock_peer_port);
    return fd;
}

long sys_sendto(struct proc *p)
{
    struct file *f = getf(p, (int)p->trapframe->a0);
    if (!f || f->type != FD_SOCKET)
        return -EBADF;
    u64 buf = p->trapframe->a1;
    u64 len = p->trapframe->a2;
    if (f->sock_type == SOCK_STREAM)
        return file_write(f, buf, len);

    int rc = socket_bind_ephemeral(f);
    if (rc < 0)
        return rc;

    struct file *dst = NULL;
    if (f->sock_type == SOCK_DGRAM) {
        u16 port = sockaddr_port(p, p->trapframe->a4, p->trapframe->a5);
        if (port == 0)
            port = f->sock_peer_port;
        f->sock_peer_port = port;
        dst = find_bound_socket(port, SOCK_DGRAM, 0);
    }
    if (!dst)
        return (long)len;
    dst->sock_peer_port = f->sock_port;
    return socket_deliver_user(dst, buf, len);
}

long sys_recvfrom(struct proc *p)
{
    struct file *f = getf(p, (int)p->trapframe->a0);
    if (!f || f->type != FD_SOCKET)
        return -EBADF;
    copy_sockaddr(p, p->trapframe->a4, p->trapframe->a5, f->sock_peer_port);
    return file_read(f, p->trapframe->a1, p->trapframe->a2);
}

