long sys_fcntl(struct proc *p)
{
    int fd = (int)p->trapframe->a0;
    int cmd = (int)p->trapframe->a1;
    u64 arg = p->trapframe->a2;
    struct file *f = getf(p, fd);
    if (!f)
        return -EBADF;

    switch (cmd) {
    case F_DUPFD:
    case F_DUPFD_CLOEXEC: {
        int start = (int)arg;
        if (start < 0)
            start = 0;
        for (int i = start; i < NOFILE; i++) {
            if (!p->ofile[i]) {
                p->ofile[i] = file_dup(f);
                return i;
            }
        }
        return -EMFILE;
    }
    case F_GETFD:
    case F_SETFD:
    case F_SETFL:
        return 0;
    case F_GETFL:
        return f->writable ? (f->readable ? 2 : 1) : 0;
    default:
        return 0;
    }
}

long sys_unlinkat(struct proc *p)
{
    char path[128], abs[160];
    if (fetch_str(p, p->trapframe->a1, path, sizeof(path)) < 0)
        return -EFAULT;
    long rr = resolve_at(p, (int)p->trapframe->a0, path, abs, sizeof(abs));
    if (rr < 0)
        return rr;
    ramfs_unlink(abs);
    return 0;
}

long sys_renameat2(struct proc *p)
{
    char oldpath[128], newpath[128], oldabs[160], newabs[160];
    if (fetch_str(p, p->trapframe->a1, oldpath, sizeof(oldpath)) < 0 ||
        fetch_str(p, p->trapframe->a3, newpath, sizeof(newpath)) < 0)
        return -EFAULT;
    long rr = resolve_at(p, (int)p->trapframe->a0, oldpath, oldabs, sizeof(oldabs));
    if (rr < 0)
        return rr;
    rr = resolve_at(p, (int)p->trapframe->a2, newpath, newabs, sizeof(newabs));
    if (rr < 0)
        return rr;
    if (ramfs_rename(oldabs, newabs) == 0)
        return 0;
    return -ENOENT;
}

