static int fetch_str(struct proc *p, u64 ua, char *buf, int max)
{
    for (int i = 0; i < max; i++) {
        char c;
        if (copyin(p->pagetable, &c, ua + (u64)i, 1) < 0)
            return -1;
        buf[i] = c;
        if (c == 0)
            return i;
    }
    return -1;
}

long sys_clone(struct proc *p)
{
    return clone(p->trapframe->a0, p->trapframe->a1, p->trapframe->a2,
                 p->trapframe->a3, p->trapframe->a4);
}

long sys_clone3(struct proc *p)
{
    struct clone_args {
        u64 flags;
        u64 pidfd;
        u64 child_tid;
        u64 parent_tid;
        u64 exit_signal;
        u64 stack;
        u64 stack_size;
        u64 tls;
        u64 set_tid;
        u64 set_tid_size;
        u64 cgroup;
    } args;
    u64 uargs = p->trapframe->a0;
    u64 size = p->trapframe->a1;
    if (!uargs || size < 64)
        return -EINVAL;
    memset(&args, 0, sizeof(args));
    u64 n = size < sizeof(args) ? size : sizeof(args);
    if (copyin(p->pagetable, &args, uargs, n) < 0)
        return -EFAULT;
    if (args.set_tid || args.set_tid_size || args.cgroup)
        return -EINVAL;

    u64 newsp = args.stack;
    if (args.stack_size)
        newsp = args.stack + args.stack_size;
    return clone(args.flags, newsp, args.parent_tid, args.tls,
                 args.child_tid);
}

