long sys_execve(struct proc *p)
{
    char path[128];
    char argstore[16][128];
    char envstore[16][128];
    char *argv[17];
    char *envp[17];

    if (fetch_str(p, p->trapframe->a0, path, sizeof(path)) < 0)
        return -EFAULT;

    /* Resolve a relative program path against the process cwd. */
    char abspath[160];
    if (path[0] != '/') {
        const char *r = path;
        while (r[0] == '.' && r[1] == '/')
            r += 2;
        int k = 0;
        for (const char *c = p->cwd; *c && k < (int)sizeof(abspath) - 1; c++)
            abspath[k++] = *c;
        if (k == 0 || abspath[k - 1] != '/')
            if (k < (int)sizeof(abspath) - 1)
                abspath[k++] = '/';
        for (const char *c = r; *c && k < (int)sizeof(abspath) - 1; c++)
            abspath[k++] = *c;
        abspath[k] = 0;
    } else {
        strlcpy(abspath, path, sizeof(abspath));
    }

    int argc = 0;
    u64 uargv = p->trapframe->a1;
    if (uargv) {
        for (; argc < 16; argc++) {
            u64 ptr;
            if (copyin(p->pagetable, &ptr, uargv + (u64)argc * 8, 8) < 0)
                return -EFAULT;
            if (ptr == 0)
                break;
            if (fetch_str(p, ptr, argstore[argc], 128) < 0)
                return -EFAULT;
            argv[argc] = argstore[argc];
        }
    }
    argv[argc] = NULL;

    int envc = 0;
    u64 uenvp = p->trapframe->a2;
    if (uenvp) {
        for (; envc < 16; envc++) {
            u64 ptr;
            if (copyin(p->pagetable, &ptr, uenvp + (u64)envc * 8, 8) < 0)
                return -EFAULT;
            if (ptr == 0)
                break;
            if (fetch_str(p, ptr, envstore[envc], 128) < 0)
                return -EFAULT;
            envp[envc] = envstore[envc];
        }
    }
    envp[envc] = NULL;

    return exec_replace(abspath, argv, envp);
}

