long sys_setuid(struct proc *p)
{
    int uid = (int)p->trapframe->a0;
    if (uid < 0)
        return -EINVAL;
    p->uid = p->euid = uid;
    return 0;
}

long sys_setgid(struct proc *p)
{
    int gid = (int)p->trapframe->a0;
    if (gid < 0)
        return -EINVAL;
    p->gid = p->egid = gid;
    if (p->ngroups > 0)
        p->groups[0] = (u32)gid;
    return 0;
}

long sys_setreuid(struct proc *p)
{
    int ruid = (int)p->trapframe->a0;
    int euid = (int)p->trapframe->a1;
    if (ruid < -1 || euid < -1)
        return -EINVAL;
    if (ruid >= 0)
        p->uid = ruid;
    if (euid >= 0)
        p->euid = euid;
    return 0;
}

long sys_setregid(struct proc *p)
{
    int rgid = (int)p->trapframe->a0;
    int egid = (int)p->trapframe->a1;
    if (rgid < -1 || egid < -1)
        return -EINVAL;
    if (rgid >= 0)
        p->gid = rgid;
    if (egid >= 0)
        p->egid = egid;
    if (p->ngroups > 0)
        p->groups[0] = (u32)p->gid;
    return 0;
}

long sys_getgroups(struct proc *p)
{
    int size = (int)p->trapframe->a0;
    u64 ulist = p->trapframe->a1;
    if (size < 0)
        return -EINVAL;
    if (size == 0)
        return p->ngroups;
    if (size < p->ngroups)
        return -EINVAL;
    for (int i = 0; i < p->ngroups; i++) {
        u32 gid = p->groups[i];
        if (copyout(p->pagetable, ulist + (u64)i * 4, &gid, 4) < 0)
            return -EFAULT;
    }
    return p->ngroups;
}

long sys_setgroups(struct proc *p)
{
    int size = (int)p->trapframe->a0;
    u64 ulist = p->trapframe->a1;
    if (p->euid != 0)
        return -EPERM;
    if (size < 0 || size > 8)
        return -EINVAL;
    for (int i = 0; i < size; i++) {
        u32 gid;
        if (copyin(p->pagetable, &gid, ulist + (u64)i * 4, 4) < 0)
            return -EFAULT;
        p->groups[i] = gid;
    }
    p->ngroups = size;
    return 0;
}

long sys_getpgid(struct proc *p)
{
    int pid = (int)p->trapframe->a0;
    if (pid < 0)
        return -ESRCH;
    struct proc *target = pid == 0 ? p : proc_find(pid);
    if (!target)
        return -ESRCH;
    return target->pgid;
}

long sys_getsid(struct proc *p)
{
    int pid = (int)p->trapframe->a0;
    if (pid < 0)
        return -ESRCH;
    struct proc *target = pid == 0 ? p : proc_find(pid);
    if (!target)
        return -ESRCH;
    return target->sid;
}

long sys_setpgid(struct proc *p)
{
    int pid = (int)p->trapframe->a0;
    int pgid = (int)p->trapframe->a1;
    if (pgid < 0)
        return -EINVAL;
    if (pid < 0)
        return -ESRCH;

