/* Kernel trap dispatch (S-mode). Handles the periodic timer (preemption) and
 * panics on any unexpected exception. */
#include "kernel/types.h"
#include "kernel/riscv.h"
#include "kernel/trap.h"
#include "kernel/proc.h"
#include "kernel/printk.h"

void trap_init(void)
{
    w_stvec((u64)kernelvec);
}

/* Decode the device interrupt: 2 = timer, 1 = other known, 0 = not a device. */
int dev_intr(u64 scause)
{
    if (!(scause & SCAUSE_INT))
        return 0;
    switch (scause & 0xff) {
    case IRQ_S_TIMER:
        timer_tick();
        return 2;
    case IRQ_S_SOFT:
        w_sip(r_sip() & ~2UL);   /* clear SSIP */
        return 1;
    case IRQ_S_EXT:
        return 1;                /* no external sources enabled yet */
    default:
        return 0;
    }
}

void kerneltrap(void)
{
    u64 sepc = r_sepc();
    u64 sstatus = r_sstatus();
    u64 scause = r_scause();

    if ((sstatus & SSTATUS_SPP) == 0)
        panic("kerneltrap: not from supervisor mode (scause=%lx)",
              (unsigned long)scause);
    if (intr_get())
        panic("kerneltrap: interrupts enabled");

    int which = dev_intr(scause);
    if (which == 0)
        panic("kerneltrap: scause=%lx sepc=%lx stval=%lx",
              (unsigned long)scause, (unsigned long)sepc,
              (unsigned long)r_stval());

    /* Preempt the running kernel thread on a timer tick. */
    struct proc *p = myproc();
    if (which == 2 && p && p->state == RUNNING)
        yield();

    /* yield()/other traps may have clobbered these CSRs; restore. */
    w_sepc(sepc);
    w_sstatus(sstatus);
}
