            yield();
        }
    } else if ((scause == 12 || scause == 13 || scause == 15) &&
               proc_handle_page_fault(r_stval()) == 0) {
        /* Shared-VM threads have per-thread roots; sync pages on demand. */
    } else {
        printk("usertrap: fault scause=%lx epc=%lx stval=%lx (pid %d) -> kill\n",
               (unsigned long)scause, (unsigned long)r_sepc(),
               (unsigned long)r_stval(), p->pid);
        proc_exit(-1);
    }

    if (p->killed)
        proc_exit_signal(p->killed);

    usertrapret();
}

/* Return to user mode via the trampoline. */
void usertrapret(void)
{
    struct proc *p = myproc();

    arch_intr_off();

    /* Send user traps to uservec in the trampoline page. */
    w_stvec(TRAMPOLINE + ((u64)uservec - (u64)trampoline));

    p->trapframe->kernel_satp = r_satp();
    p->trapframe->kernel_sp = p->kstack + KSTACK_SIZE;
    p->trapframe->kernel_trap = (u64)usertrap;
    p->trapframe->kernel_hartid = 0;

    u64 x = r_sstatus();
    x &= ~SSTATUS_SPP;   /* return to user mode */
    x |= SSTATUS_SPIE;   /* enable interrupts in user mode */
    w_sstatus(x);

    w_sepc(p->trapframe->epc);

    u64 satp = MAKE_SATP((u64)p->pagetable);
    u64 fn = TRAMPOLINE + ((u64)userret - (u64)trampoline);
    ((void (*)(u64))fn)(satp);
}

/* First time a freshly created user process is scheduled. */
void forkret(void)
{
    usertrapret();
}
/* RISC-V Sv39 paging.
 *
 * Kernel: a single root page table identity-maps the low 4 GiB with 1 GiB
 * gigapages (covers all RAM + MMIO, VA == PA), plus the trampoline page at the
 * top of the address space.
 *
 * User: each process gets its own Sv39 table (4 KiB leaves) created with
 * walk()/mappages(), sharing the trampoline and its own trapframe at the top.
 */
#include "kernel/types.h"
#include "kernel/param.h"
#include "kernel/memlayout.h"
#include "kernel/riscv.h"
#include "kernel/mm.h"
#include "kernel/proc.h"
#include "kernel/vm.h"
#include "kernel/printk.h"

void *memmove(void *dst, const void *src, size_t n);

#define NGIGA 4

#define PX(level, va)  (((va) >> (12 + 9 * (level))) & 0x1FF)
#define PTE2PA(pte)    (((pte) >> 10) << 12)
#define PA2PTE(pa)     ((((u64)(pa)) >> 12) << 10)
#define PTE_FLAGS(pte) ((pte) & 0x3FF)

extern char trampoline[];   /* arch/riscv/trampoline.S, page-aligned */

static u64 kernel_pagetable[512] __attribute__((aligned(4096)));

/* Walk to the level-0 PTE for va, allocating interior tables when alloc != 0. */
static u64 *walk(pagetable_t pt, u64 va, int alloc)
{
    if (va >= MAXVA)
        return NULL;
    for (int level = 2; level > 0; level--) {
        u64 *pte = &pt[PX(level, va)];
        if (*pte & PTE_V) {
            pt = (pagetable_t)PTE2PA(*pte);
        } else {
            if (!alloc)
                return NULL;
            void *np = kalloc_page();
            if (!np)
                return NULL;
            *pte = PA2PTE((u64)np) | PTE_V;
            pt = np;
        }
    }
    return &pt[PX(0, va)];
}

int mappages(pagetable_t pt, u64 va, u64 size, u64 pa, int perm)
{
    if (size == 0)
        return -1;
    u64 a = PGROUNDDOWN(va);
    u64 last = PGROUNDDOWN(va + size - 1);
    for (;;) {
        u64 *pte = walk(pt, a, 1);
        if (!pte)
            return -1;
        if (*pte & PTE_V)
            return -1;
        *pte = PA2PTE(pa) | perm | PTE_V;
        if (a == last)
            break;
        a += PGSIZE;
        pa += PGSIZE;
    }
    return 0;
}

u64 walkaddr(pagetable_t pt, u64 va)
{
    u64 *pte = walk(pt, va, 0);
    if (!pte || !(*pte & PTE_V) || !(*pte & PTE_U))
        return 0;
    return PTE2PA(*pte);
}

pagetable_t uvmcreate(void)
{
    return (pagetable_t)kalloc_page();   /* zeroed by the allocator */
}

/* Grow a user image from oldsz to newsz, mapping fresh zeroed pages. */
u64 uvmalloc(pagetable_t pt, u64 oldsz, u64 newsz, int perm)
{
    if (newsz <= oldsz)
        return oldsz;
    for (u64 a = PGROUNDUP(oldsz); a < newsz; a += PGSIZE) {
        if (walkaddr(pt, a) != 0)
            continue;
        void *mem = kalloc_page();
        if (!mem)
            return 0;
        if (mappages(pt, a, PGSIZE, (u64)mem, perm | PTE_U) < 0) {
            kfree_page(mem);
            return 0;
        }
    }
    return newsz;
}

void uvmunmap(pagetable_t pt, u64 va, u64 npages, int do_free)
{
    for (u64 a = va; a < va + npages * PGSIZE; a += PGSIZE) {
        u64 *pte = walk(pt, a, 0);
        if (!pte || !(*pte & PTE_V))
            continue;
        if (do_free)
            kfree_page((void *)PTE2PA(*pte));
        *pte = 0;
    }
}

/* Recursively free page-table pages. Leaf mappings must already be removed. */
static void freewalk(pagetable_t pt)
{
    for (int i = 0; i < 512; i++) {
        u64 pte = pt[i];
        if ((pte & PTE_V) && (pte & (PTE_R | PTE_W | PTE_X)) == 0) {
            freewalk((pagetable_t)PTE2PA(pte));
            pt[i] = 0;
        }
    }
    kfree_page(pt);
}

void uvmfree(pagetable_t pt, u64 sz)
{
    if (sz > 0)
        uvmunmap(pt, 0, PGROUNDUP(sz) / PGSIZE, 1);
    freewalk(pt);
}

