int uvmcopy_page(pagetable_t old, pagetable_t new, u64 va)
{
    u64 a = PGROUNDDOWN(va);
    u64 *pte = walk(old, a, 0);
    if (!pte || !(*pte & PTE_V))
        return 0;
    u64 pa = PTE2PA(*pte);
    int flags = PTE_FLAGS(*pte);
    void *mem = kalloc_page();
    if (!mem)
        return -1;
    memmove(mem, (void *)pa, PGSIZE);
    if (mappages(new, a, PGSIZE, (u64)mem, flags) < 0) {
        kfree_page(mem);
        return -1;
    }
    return 0;
}

int uvmshare_page(pagetable_t old, pagetable_t new, u64 va)
{
    u64 a = PGROUNDDOWN(va);
    u64 *pte = walk(old, a, 0);
    if (!pte || !(*pte & PTE_V))
        return 0;
    void *pa = (void *)PTE2PA(*pte);
    kref_page(pa);
    if (mappages(new, a, PGSIZE, (u64)pa, PTE_FLAGS(*pte)) < 0) {
        kfree_page(pa);
        return -1;
    }
    return 0;
}

int uvmcopy_cow(pagetable_t old, pagetable_t new, u64 start, u64 end)
{
    for (u64 a = PGROUNDDOWN(start); a < end; a += PGSIZE) {
        u64 *pte = walk(old, a, 0);
        if (!pte || !(*pte & PTE_V))
            continue;
        u64 pa = PTE2PA(*pte);
        int flags = PTE_FLAGS(*pte);
        if (flags & PTE_W) {
            flags = (flags & ~PTE_W) | PTE_COW;
            *pte = PA2PTE(pa) | flags;
        }
        kref_page((void *)pa);
        if (mappages(new, a, PGSIZE, pa, flags) < 0) {
            kfree_page((void *)pa);
            return -1;
        }
    }
    sfence_vma();
    return 0;
}

int uvmcow(pagetable_t pt, u64 va)
{
    u64 a = PGROUNDDOWN(va);
    u64 *pte = walk(pt, a, 0);
    if (!pte || !(*pte & PTE_V) || !(*pte & PTE_U) || !(*pte & PTE_COW))
        return 1;

    u64 oldpa = PTE2PA(*pte);
    int flags = (PTE_FLAGS(*pte) | PTE_W) & ~PTE_COW;
    void *mem = kalloc_page();
    if (!mem)
        return -1;
    memmove(mem, (void *)oldpa, PGSIZE);
    *pte = PA2PTE((u64)mem) | flags | PTE_V;
    kfree_page((void *)oldpa);
    sfence_vma();
    return 0;
}

int uvmprotect(pagetable_t pt, u64 va, u64 len, int perm, int alloc_missing)
{
    if (len == 0)
        return 0;
    if (perm & PERM_W)
        perm |= PERM_R;
    int access = perm & (PERM_R | PERM_W | PERM_X);

    u64 start = PGROUNDDOWN(va);
    u64 end = PGROUNDUP(va + len);
    for (u64 a = start; a < end; a += PGSIZE) {
        u64 *pte = walk(pt, a, 0);
        if (!pte || !(*pte & PTE_V) || !(*pte & PTE_U)) {
            if (!alloc_missing)
                return -1;
            if (access == 0)
                continue;
            void *mem = kalloc_page();
            if (!mem)
                return -1;
            if (mappages(pt, a, PGSIZE, (u64)mem, perm | PERM_U) < 0) {
                kfree_page(mem);
                return -1;
            }
            continue;
        }

        if ((access & PERM_W) && (*pte & PTE_COW)) {
            if (uvmcow(pt, a) < 0)
                return -1;
            pte = walk(pt, a, 0);
            if (!pte || !(*pte & PTE_V))
                return -1;
        }

        u64 pa = PTE2PA(*pte);
        if (access == 0) {
            kfree_page((void *)pa);
            *pte = 0;
            continue;
        }
        u64 keep = *pte & (PTE_A | PTE_D);
        if ((*pte & PTE_COW) && !(access & PERM_W))
            keep |= PTE_COW;
        *pte = PA2PTE(pa) | PTE_V | PTE_U | keep |
               access;
    }
    sfence_vma();
    return 0;
}

/* Copy mapped pages in [start, end) from `old` into `new` (same permissions). */
int uvmcopy(pagetable_t old, pagetable_t new, u64 start, u64 end)
{
    for (u64 a = PGROUNDDOWN(start); a < end; a += PGSIZE)
        if (uvmcopy_page(old, new, a) < 0)
            return -1;
    return 0;
}

int copyout(pagetable_t pt, u64 dstva, const void *src, u64 len)
{
    const char *s = src;
    while (len > 0) {
        u64 va0 = PGROUNDDOWN(dstva);
        if (uvmcow(pt, va0) < 0)
            return -1;
        u64 pa0 = walkaddr(pt, va0);
        if (pa0 == 0)
            return -1;
        u64 n = PGSIZE - (dstva - va0);
        if (n > len)
            n = len;
        memmove((void *)(pa0 + (dstva - va0)), s, n);
        len -= n;
        s += n;
        dstva = va0 + PGSIZE;
    }
    return 0;
}

int copyin(pagetable_t pt, void *dst, u64 srcva, u64 len)
{
    char *d = dst;
    while (len > 0) {
        u64 va0 = PGROUNDDOWN(srcva);
        u64 pa0 = walkaddr(pt, va0);
        if (pa0 == 0)
            return -1;
        u64 n = PGSIZE - (srcva - va0);
        if (n > len)
            n = len;
        memmove(d, (void *)(pa0 + (srcva - va0)), n);
        len -= n;
        d += n;
        srcva = va0 + PGSIZE;
    }
    return 0;
}

/* Build a user page table with the trampoline + the process's trapframe. */
pagetable_t proc_pagetable(struct proc *p)
{
    pagetable_t pt = uvmcreate();
    if (!pt)
        return NULL;
    if (mappages(pt, TRAMPOLINE, PGSIZE, (u64)trampoline, PTE_R | PTE_X) < 0) {
        uvmfree(pt, 0);
        return NULL;
    }
    if (mappages(pt, TRAPFRAME, PGSIZE, (u64)p->trapframe, PTE_R | PTE_W) < 0) {
        uvmunmap(pt, TRAMPOLINE, 1, 0);
        uvmfree(pt, 0);
        return NULL;
    }
    return pt;
}

void proc_freepagetable(pagetable_t pt, u64 sz)
{
    uvmunmap(pt, TRAMPOLINE, 1, 0);
    uvmunmap(pt, TRAPFRAME, 1, 0);
    uvmfree(pt, sz);
}

void kvm_init(void)
{
    for (int i = 0; i < NGIGA; i++) {
        u64 pa = (u64)i << 30;
        kernel_pagetable[i] = (PA2PTE(pa)) |
            PTE_V | PTE_R | PTE_W | PTE_X | PTE_A | PTE_D;
    }
    /* Map the trampoline so execution survives the satp switch on the way in. */
    if (mappages(kernel_pagetable, TRAMPOLINE, PGSIZE, (u64)trampoline,
                 PTE_R | PTE_X) < 0)
        panic("kvm_init: trampoline map failed");
}

void kvm_enable(void)
{
    sfence_vma();
    w_satp(MAKE_SATP((u64)kernel_pagetable));
    sfence_vma();
    printk("[mmu] Sv39 paging enabled (kernel identity %d GiB + trampoline)\n",
           NGIGA);
}

