struct file *console_file(void)
{
    the_console.ref++;
    return &the_console;
}

struct file *file_alloc(void)
{
    for (int i = 0; i < NFILE; i++) {
        if (ftable[i].ref == 0) {
            memset(&ftable[i], 0, sizeof(ftable[i]));
            ftable[i].ref = 1;
            ftable[i].type = FD_NONE;
            return &ftable[i];
        }
    }
    return NULL;
}

struct file *file_dup(struct file *f)
{
    f->ref++;
    return f;
}

void file_close(struct file *f)
{
    if (!f || f->ref < 1)
        return;
    if (--f->ref > 0)
        return;
    if (f->type == FD_PIPE && f->pipe)
        pipe_close(f->pipe, f->writable);
    if (f->type == FD_SOCKET) {
        socket_unregister_file(f);
        if (f->sock_peer && f->sock_peer->sock_peer == f)
            f->sock_peer->sock_peer = NULL;
        if (f->sock_pending && f->sock_pending->ref > 0)
            file_close(f->sock_pending);
    }
    if (f == &the_console)
        return;
    f->type = FD_NONE;
}

