        strlcpy(ramtab[i].path + newlen, suffix,
                sizeof(ramtab[i].path) - newlen);
    }
    return 0;
}

u8 *ramfs_page_at(struct ramnode *rn, u64 off, int alloc)
{
    if (!rn || rn->is_dir || off >= RAMFS_FILE_CAP)
        return NULL;
    u64 idx = off / PGSIZE;
    if (idx >= RAMFS_MAX_PAGES)
        return NULL;
    if (!rn->pages[idx] && alloc) {
        rn->pages[idx] = kalloc_page();
        if (!rn->pages[idx])
            return NULL;
    }
    return rn->pages[idx];
}

int ramfs_resize(struct ramnode *rn, u64 len, int alloc)
{
    if (!rn || rn->is_dir || len > RAMFS_FILE_CAP)
        return -1;
    if (alloc) {
        for (u64 off = 0; off < len; off += PGSIZE)
            if (!ramfs_page_at(rn, off, 1))
                return -1;
    }
    if (len < rn->size) {
        u64 tail = len & (PGSIZE - 1);
        if (tail) {
            u8 *pg = ramfs_page_at(rn, len, 0);
            if (pg)
                memset(pg + tail, 0, PGSIZE - tail);
        }
        u64 first_free = PGROUNDUP(len) / PGSIZE;
        for (u64 i = first_free; i < RAMFS_MAX_PAGES; i++) {
            if (rn->pages[i]) {
                kfree_page(rn->pages[i]);
                rn->pages[i] = NULL;
            }
        }
    }
    rn->size = len;
    return 0;
}

int ramfs_clone(struct ramnode *dst, struct ramnode *src)
{
    if (!dst || !src)
        return -1;
    if (ramfs_resize(dst, 0, 0) < 0)
        return -1;
    dst->mode = src->mode;
    dst->is_symlink = src->is_symlink;
    strlcpy(dst->target, src->target, sizeof(dst->target));
    if (src->size > RAMFS_FILE_CAP)
        return -1;
    for (u64 off = 0; off < src->size; off += PGSIZE) {
        u8 *sp = ramfs_page_at(src, off, 0);
        if (!sp)
            continue;
        u8 *dp = ramfs_page_at(dst, off, 1);
        if (!dp)
            return -1;
        memcpy(dp, sp, PGSIZE);
    }
    dst->size = src->size;
    return 0;
}

int ramfs_readdir(struct ramnode *dir,
                  int (*cb)(const char *, u32, u8, void *), void *arg)
{
    if (!dir || !dir->is_dir)
        return -1;

    if (cb(".", 0x80000000U, 4, arg))
        return 0;
    if (cb("..", 0x80000000U, 4, arg))
        return 0;

    const char *base = dir->path;
    u64 blen = strlen(base);
    int root = (blen == 1 && base[0] == '/');

    for (int i = 0; i < NRAM; i++) {
        if (!ramtab[i].used || &ramtab[i] == dir)
            continue;

        const char *rest = NULL;
        if (root) {
            if (ramtab[i].path[0] != '/')
                continue;
            rest = ramtab[i].path + 1;
        } else {
            if (strncmp(ramtab[i].path, base, blen) != 0 ||
                ramtab[i].path[blen] != '/')
                continue;
            rest = ramtab[i].path + blen + 1;
        }
        if (!rest || rest[0] == '\0')
            continue;

        int nested = 0;
        for (const char *s = rest; *s; s++) {
            if (*s == '/') {
                nested = 1;
                break;
            }
        }
        if (nested)
            continue;

        u8 type = ramtab[i].is_dir ? 4 : 8; /* DT_DIR / DT_REG */
        if (cb(rest, 0x80000000U | (u32)i, type, arg))
            return 0;
    }
    return 0;
}

/* ---- read / write ---- */

static long ramfs_read_user(struct ramnode *rn, u64 off, u64 uaddr, u64 n)
{
    struct proc *p = myproc();
    if (!rn || off >= rn->size || off >= RAMFS_FILE_CAP)
        return 0;
    u64 total = min_u64(n, rn->size - off);
    total = min_u64(total, RAMFS_FILE_CAP - off);
    u64 done = 0;
    u8 zeros[128];
    memset(zeros, 0, sizeof(zeros));
    while (done < total) {
        u64 pos = off + done;
        u64 page_off = pos & (PGSIZE - 1);
        u64 chunk = min_u64(total - done, PGSIZE - page_off);
        u8 *pg = ramfs_page_at(rn, pos, 0);
        if (pg) {
            if (copyout(p->pagetable, uaddr + done, pg + page_off, chunk) < 0)
                return -1;
        } else {
            u64 zdone = 0;
            while (zdone < chunk) {
                u64 zchunk = min_u64(chunk - zdone, sizeof(zeros));
                if (copyout(p->pagetable, uaddr + done + zdone,
                            zeros, zchunk) < 0)
                    return -1;
                zdone += zchunk;
            }
        }
        done += chunk;
    }
    return (long)done;
}

static long ramfs_write_user(struct ramnode *rn, u64 off, u64 uaddr, u64 n)
{
    struct proc *p = myproc();
    if (!rn || off > RAMFS_FILE_CAP)
        return -1;
    n = min_u64(n, RAMFS_FILE_CAP - off);
    u64 done = 0;
    while (done < n) {
        u64 pos = off + done;
        u64 page_off = pos & (PGSIZE - 1);
        u64 chunk = min_u64(n - done, PGSIZE - page_off);
        u8 *pg = ramfs_page_at(rn, pos, 1);
        if (!pg)
            return done ? (long)done : -1;
        if (copyin(p->pagetable, pg + page_off, uaddr + done, chunk) < 0)
            return -1;
        done += chunk;
    }
    if (off + done > rn->size)
        rn->size = off + done;
    return (long)done;
}

static long ramfs_read_k(struct ramnode *rn, u64 off, void *kbuf, u64 n)
{
    if (!rn || off >= rn->size || off >= RAMFS_FILE_CAP)
        return 0;
    u64 total = min_u64(n, rn->size - off);
    total = min_u64(total, RAMFS_FILE_CAP - off);
    u64 done = 0;
    char *dst = kbuf;
    while (done < total) {
        u64 pos = off + done;
        u64 page_off = pos & (PGSIZE - 1);
        u64 chunk = min_u64(total - done, PGSIZE - page_off);
        u8 *pg = ramfs_page_at(rn, pos, 0);
        if (pg)
            memcpy(dst + done, pg + page_off, chunk);
        else
            memset(dst + done, 0, chunk);
        done += chunk;
    }
    return (long)done;
}

static long ramfs_write_k(struct ramnode *rn, u64 off, const void *kbuf, u64 n)
{
    if (!rn || off > RAMFS_FILE_CAP)
        return -1;
    n = min_u64(n, RAMFS_FILE_CAP - off);
    u64 done = 0;
    const char *src = kbuf;
    while (done < n) {
        u64 pos = off + done;
        u64 page_off = pos & (PGSIZE - 1);
        u64 chunk = min_u64(n - done, PGSIZE - page_off);
        u8 *pg = ramfs_page_at(rn, pos, 1);
        if (!pg)
            return done ? (long)done : -1;
        memcpy(pg + page_off, src + done, chunk);
        done += chunk;
    }
    if (off + done > rn->size)
        rn->size = off + done;
    return (long)done;
}

static u8 random_byte(void)
{
    random_state = random_state * 6364136223846793005ULL + 1442695040888963407ULL;
    return (u8)(random_state >> 32);
}

static long random_read_user(u64 uaddr, u64 n)
{
    struct proc *p = myproc();
    for (u64 i = 0; i < n; i++) {
        u8 b = random_byte();
        if (copyout(p->pagetable, uaddr + i, &b, 1) < 0)
            return -1;
    }
    return (long)n;
}

static long zero_read_user(u64 uaddr, u64 n)
{
    struct proc *p = myproc();
    u8 zeros[128];
    memset(zeros, 0, sizeof(zeros));
    u64 done = 0;
    while (done < n) {
        u64 chunk = n - done;
        if (chunk > sizeof(zeros))
            chunk = sizeof(zeros);
        if (copyout(p->pagetable, uaddr + done, zeros, chunk) < 0)
            return -1;
        done += chunk;
    }
    return (long)n;
}

