long file_read(struct file *f, u64 uaddr, u64 n)
{
    struct proc *p = myproc();
    if (!f->readable)
        return -1;

    switch (f->type) {
    case FD_DEVICE:
        if (f->dev == DEV_RANDOM)
            return random_read_user(uaddr, n);
        if (f->dev == DEV_ZERO)
            return zero_read_user(uaddr, n);
        return 0;   /* console/tty: no buffered stdin yet -> EOF */
    case FD_PIPE:
        return pipe_read(f->pipe, uaddr, n);
    case FD_SOCKET:
        return socket_dequeue_user(f, uaddr, n);
    case FD_INODE: {
        u8 kbuf[1024];
        u64 done = 0;
        while (done < n) {
            u64 chunk = n - done;
            if (chunk > sizeof(kbuf))
                chunk = sizeof(kbuf);
            long r = ext4_pread(f->ino, kbuf, f->off, chunk);
            if (r <= 0)
                break;
            if (copyout(p->pagetable, uaddr + done, kbuf, (u64)r) < 0)
                return -1;
            f->off += (u64)r;
            done += (u64)r;
            if ((u64)r < chunk)
                break;
        }
        return (long)done;
    }
    case FD_RAMFS: {
        struct ramnode *rn = f->rnode;
        long r = ramfs_read_user(rn, f->off, uaddr, n);
        if (r > 0)
            f->off += (u64)r;
        return r;
    }
    default:
        return -1;
    }
}

static long ramfs_write(struct file *f, u64 uaddr, u64 n)
{
    struct ramnode *rn = f->rnode;
    if (!rn)
        return -1;
    long r = ramfs_write_user(rn, f->off, uaddr, n);
    if (r > 0)
        f->off += (u64)r;
    return r;
}

long file_write(struct file *f, u64 uaddr, u64 n)
{
    if (!f->writable)
        return -1;

    switch (f->type) {
    case FD_DEVICE: {
        if (f->dev == DEV_NULL || f->dev == DEV_RANDOM || f->dev == DEV_ZERO)
            return (long)n;
        struct proc *p = myproc();
        char buf[256];
        u64 done = 0;
        while (done < n) {
            u64 c = n - done;
            if (c > sizeof(buf))
                c = sizeof(buf);
            if (copyin(p->pagetable, buf, uaddr + done, c) < 0)
                return -1;
            for (u64 i = 0; i < c; i++)
                uart_putc(buf[i]);
            done += c;
        }
        return (long)n;
    }
    case FD_PIPE:
        return pipe_write(f->pipe, uaddr, n);
    case FD_SOCKET:
        return socket_enqueue_user(f->sock_peer, uaddr, n);
    case FD_RAMFS:
        return ramfs_write(f, uaddr, n);
    default:
        return -1;
    }
}

/* Kernel-buffer variants (used by sendfile). */
long file_read_k(struct file *f, void *kbuf, u64 n)
{
    if (!f->readable)
        return -1;
    if (f->type == FD_INODE) {
        long r = ext4_pread(f->ino, kbuf, f->off, n);
        if (r > 0)
            f->off += (u64)r;
        return r;
    }
    if (f->type == FD_RAMFS) {
        struct ramnode *rn = f->rnode;
        if (!rn || f->off >= rn->size)
            return 0;
        long r = ramfs_read_k(rn, f->off, kbuf, n);
        if (r > 0)
            f->off += (u64)r;
        return r;
    }
    if (f->type == FD_DEVICE && f->dev == DEV_RANDOM) {
        u8 *dst = kbuf;
        for (u64 i = 0; i < n; i++)
            dst[i] = random_byte();
        return (long)n;
    }
    if (f->type == FD_DEVICE && f->dev == DEV_ZERO) {
        memset(kbuf, 0, n);
        return (long)n;
    }
    return -1;
}

long file_pread_k(struct file *f, void *kbuf, u64 off, u64 n)
{
    if (!f->readable)
        return -1;
    if (f->type == FD_INODE)
        return ext4_pread(f->ino, kbuf, off, n);
    if (f->type == FD_RAMFS) {
        struct ramnode *rn = f->rnode;
        return ramfs_read_k(rn, off, kbuf, n);
    }
    return -1;
}

long file_write_k(struct file *f, const void *kbuf, u64 n)
{
    if (!f->writable)
        return -1;
    if (f->type == FD_DEVICE) {
        if (f->dev == DEV_NULL || f->dev == DEV_RANDOM || f->dev == DEV_ZERO)
            return (long)n;
        const char *b = kbuf;
        for (u64 i = 0; i < n; i++)
            uart_putc(b[i]);
        return (long)n;
    }
    if (f->type == FD_RAMFS) {
        struct ramnode *rn = f->rnode;
        if (!rn)
            return -1;
        long r = ramfs_write_k(rn, f->off, kbuf, n);
        if (r > 0)
            f->off += (u64)r;
        return r;
    }
    if (f->type == FD_PIPE)
        return pipe_write_k(f->pipe, kbuf, n);
    return -1;
}

long file_pwrite_k(struct file *f, const void *kbuf, u64 off, u64 n)
{
    if (!f->writable)
        return -1;
    if (f->type == FD_RAMFS)
        return ramfs_write_k(f->rnode, off, kbuf, n);
    return -1;
}

int file_stat(struct file *f, struct kstat *st)
{
    memset(st, 0, sizeof(*st));
    st->st_blksize = 512;
    st->st_nlink = 1;
    switch (f->type) {
    case FD_DEVICE:
        st->st_mode = S_IFCHR | 0666;
        break;
    case FD_SOCKET:
        st->st_mode = S_IFSOCK | 0600;
        break;
    case FD_PIPE:
        st->st_mode = S_IFIFO | 0600;
        break;
    case FD_INODE:
        st->st_ino = f->ino;
        st->st_size = (i64)f->size;
        st->st_mode = (f->is_dir ? S_IFDIR : S_IFREG) | 0755;
        st->st_blocks = (f->size + 511) / 512;
        break;
    case FD_RAMFS:
        st->st_size = f->rnode ? (i64)f->rnode->size : 0;
        st->st_mode = f->rnode ? f->rnode->mode :
                      (u16)((S_IFREG) | 0755);
        break;
    default:
        return -1;
    }
    return 0;
}

/* Blocking byte-stream pipe backed by a ring buffer. */
#include "kernel/types.h"
#include "kernel/mm.h"
#include "kernel/proc.h"
#include "fs/file.h"

#define PIPESIZE 512

struct pipe {
    char buf[PIPESIZE];
    u64  nread;     /* bytes consumed */
    u64  nwrite;    /* bytes produced */
    int  readopen;
    int  writeopen;
};

int copyin(pagetable_t pt, void *dst, u64 srcva, u64 len);
int copyout(pagetable_t pt, u64 dstva, const void *src, u64 len);

int pipe_alloc(struct file **rf, struct file **wf)
{
    struct pipe *pi = kzalloc(sizeof(*pi));
    if (!pi)
        return -1;
    *rf = file_alloc();
    *wf = file_alloc();
    if (!*rf || !*wf) {
        if (*rf) file_close(*rf);
        if (*wf) file_close(*wf);
        kfree(pi);
        return -1;
    }
    pi->readopen = 1;
    pi->writeopen = 1;
    pi->nread = pi->nwrite = 0;
    (*rf)->type = FD_PIPE; (*rf)->readable = 1; (*rf)->writable = 0; (*rf)->pipe = pi;
    (*wf)->type = FD_PIPE; (*wf)->readable = 0; (*wf)->writable = 1; (*wf)->pipe = pi;
    return 0;
}

void pipe_close(struct pipe *pi, int writable)
{
    if (writable) {
        pi->writeopen = 0;
        wakeup(&pi->nread);
    } else {
        pi->readopen = 0;
        wakeup(&pi->nwrite);
    }
    if (pi->readopen == 0 && pi->writeopen == 0)
        kfree(pi);
}

long pipe_write(struct pipe *pi, u64 uaddr, u64 n)
{
    struct proc *p = myproc();
    u64 i = 0;
    while (i < n) {
        if (pi->readopen == 0)
            return -1;
        if (pi->nwrite == pi->nread + PIPESIZE) {
            wakeup(&pi->nread);
            sleep(&pi->nwrite);
            continue;
        }
        char ch;
        if (copyin(p->pagetable, &ch, uaddr + i, 1) < 0)
            break;
        pi->buf[pi->nwrite++ % PIPESIZE] = ch;
        i++;
    }
    wakeup(&pi->nread);
    return (long)i;
}

long pipe_write_k(struct pipe *pi, const void *buf, u64 n)
{
    const char *src = buf;
    u64 i = 0;
    while (i < n) {
        if (pi->readopen == 0)
            return -1;
        if (pi->nwrite == pi->nread + PIPESIZE) {
            wakeup(&pi->nread);
            sleep(&pi->nwrite);
            continue;
        }
        pi->buf[pi->nwrite++ % PIPESIZE] = src[i++];
    }
    wakeup(&pi->nread);
    return (long)i;
}

long pipe_read(struct pipe *pi, u64 uaddr, u64 n)
{
    struct proc *p = myproc();
    while (pi->nread == pi->nwrite && pi->writeopen) {
        sleep(&pi->nread);
    }
    u64 i = 0;
    for (; i < n && pi->nread < pi->nwrite; i++) {
        char ch = pi->buf[pi->nread++ % PIPESIZE];
        if (copyout(p->pagetable, uaddr + i, &ch, 1) < 0)
            break;
    }
    wakeup(&pi->nwrite);
    return (long)i;
}

/* Read-only ext4 driver: superblock, group descriptors, inodes, extent trees,
 * directory lookup and file reads. Sufficient to load test binaries/scripts
 * from the contest disk. Write support and indirect (non-extent) files land in
 * later phases.
 */
#include "kernel/types.h"
#include "kernel/printk.h"
#include "fs/ext4.h"
#include "drivers/blkdev.h"

void *memcpy(void *dst, const void *src, size_t n);
int   memcmp(const void *a, const void *b, size_t n);
size_t strlen(const char *s);

/* Little-endian field readers (RISC-V/LA are LE; use byte assembly for safety). */
static u16 le16(const u8 *p) { return (u16)(p[0] | (p[1] << 8)); }
static u32 le32(const u8 *p) { return (u32)p[0] | ((u32)p[1] << 8) | ((u32)p[2] << 16) | ((u32)p[3] << 24); }

#define EXT4_SUPER_MAGIC 0xef53
#define EXT4_EXTENT_MAGIC 0xf30a
#define INCOMPAT_64BIT 0x80
#define EXT4_NDIR 15           /* i_block is 15 u32 entries (60 bytes) */
#define EXT4_BLOCK_CACHE 64
#define EXT4_LOOKUP_CACHE 128

static struct {
    int   mounted;
    u32   block_size;
    u32   inode_size;
    u32   inodes_per_group;
    u32   desc_size;           /* 32 or 64 */
    u32   first_data_block;
    u64   blocks_count;
    int   has_64bit;
} fs;

struct block_cache_entry {
    int valid;
    u64 block;
    u8  data[4096];
};

struct lookup_cache_entry {
    int valid;
    u32 parent;
    u32 ino;
    u32 len;
    char name[64];
};

static struct block_cache_entry block_cache[EXT4_BLOCK_CACHE];
static struct lookup_cache_entry lookup_cache[EXT4_LOOKUP_CACHE];
static u32 block_cache_hand;
static u32 lookup_cache_hand;

/* Read `len` bytes starting at absolute byte offset `off`. */
static int read_bytes(u64 off, void *dst, u32 len)
{
    u8 tmp[BLK_SECTOR_SIZE];
    u8 *out = dst;
    while (len) {
        u64 sec = off / BLK_SECTOR_SIZE;
        u32 within = (u32)(off % BLK_SECTOR_SIZE);
        u32 chunk = BLK_SECTOR_SIZE - within;
        if (chunk > len)
            chunk = len;
        if (blk_read(sec, tmp) < 0)
            return -1;
        memcpy(out, tmp + within, chunk);
        off += chunk;
        out += chunk;
        len -= chunk;
    }
    return 0;
}

static int read_block(u64 blk, void *buf)
{
    for (int i = 0; i < EXT4_BLOCK_CACHE; i++) {
        if (block_cache[i].valid && block_cache[i].block == blk) {
            memcpy(buf, block_cache[i].data, fs.block_size);
            return 0;
        }
    }

    u32 slot = block_cache_hand++ % EXT4_BLOCK_CACHE;
    if (read_bytes(blk * fs.block_size, block_cache[slot].data, fs.block_size) < 0)
        return -1;
    block_cache[slot].valid = 1;
    block_cache[slot].block = blk;
    memcpy(buf, block_cache[slot].data, fs.block_size);
    return 0;
}

int ext4_mount(void)
{
    u8 sb[1024];
    if (read_bytes(1024, sb, sizeof(sb)) < 0)
        return -1;
    if (le16(sb + 56) != EXT4_SUPER_MAGIC) {
        printk("[ext4] bad magic (not an ext4 filesystem)\n");
        return -1;
    }

    fs.block_size = 1024u << le32(sb + 24);
    fs.inodes_per_group = le32(sb + 40);
    fs.blocks_count = le32(sb + 4);
    fs.first_data_block = le32(sb + 20);

    u32 rev = le32(sb + 76);
    fs.inode_size = (rev >= 1) ? le16(sb + 88) : 128;
    if (fs.inode_size == 0)
        fs.inode_size = 128;

    u32 incompat = le32(sb + 96);
    fs.has_64bit = (incompat & INCOMPAT_64BIT) != 0;
    fs.desc_size = fs.has_64bit ? le16(sb + 254) : 32;
    if (fs.desc_size < 32)
        fs.desc_size = 32;

    fs.mounted = 1;
    for (int i = 0; i < EXT4_BLOCK_CACHE; i++)
        block_cache[i].valid = 0;
    for (int i = 0; i < EXT4_LOOKUP_CACHE; i++)
        lookup_cache[i].valid = 0;
    block_cache_hand = 0;
    lookup_cache_hand = 0;
    printk("[ext4] mounted: bs=%u isize=%u ipg=%u desc=%u 64bit=%d\n",
           fs.block_size, fs.inode_size, fs.inodes_per_group, fs.desc_size,
           fs.has_64bit);
    return 0;
}

/* Locate the inode-table block for the group owning `ino`. */
static int inode_table_block(u32 group, u64 *out)
{
    u32 gdt_block = fs.first_data_block + 1;
    u64 desc_off = (u64)gdt_block * fs.block_size + (u64)group * fs.desc_size;
    u8 d[64];
    if (read_bytes(desc_off, d, fs.desc_size) < 0)
        return -1;
    u64 itbl = le32(d + 8);
    if (fs.has_64bit && fs.desc_size >= 64)
        itbl |= (u64)le32(d + 40) << 32;
    *out = itbl;
    return 0;
}

/* Load the raw inode (first 128 bytes are enough for what we use). */
static int read_inode(u32 ino, u8 *out /* >= 160 bytes */)
{
    if (ino == 0)
        return -1;
    u32 group = (ino - 1) / fs.inodes_per_group;
    u32 index = (ino - 1) % fs.inodes_per_group;
    u64 itbl;
    if (inode_table_block(group, &itbl) < 0)
        return -1;
    u64 off = itbl * fs.block_size + (u64)index * fs.inode_size;
    u32 n = fs.inode_size < 160 ? fs.inode_size : 160;
    return read_bytes(off, out, n);
}

static u64 inode_size_bytes(const u8 *inode)
{
    return (u64)le32(inode + 4) | ((u64)le32(inode + 108) << 32);
}

/* Map a logical block within a file to its physical block via the extent tree.
 * Returns 0 if unmapped (sparse hole or unsupported layout). */
static u64 extent_map(const u8 *inode, u32 logical)
{
    u8 node[4096];
    const u8 *eh = inode + 40;   /* i_block area (60 bytes) holds the root node */

    for (int guard = 0; guard < 8; guard++) {
        if (le16(eh + 0) != EXT4_EXTENT_MAGIC)
            return 0;
        u16 entries = le16(eh + 2);
        u16 depth = le16(eh + 6);

        if (depth == 0) {
            for (u16 i = 0; i < entries; i++) {
                const u8 *ee = eh + 12 + i * 12;
                u32 ee_block = le32(ee + 0);
                u16 ee_len = le16(ee + 4);
                u64 start = ((u64)le16(ee + 6) << 32) | le32(ee + 8);
                if (logical >= ee_block && logical < (u32)(ee_block + ee_len))
                    return start + (logical - ee_block);
            }
            return 0;
        }
        /* interior node: pick the last index whose ei_block <= logical */
        u64 child = 0;
        for (u16 i = 0; i < entries; i++) {
            const u8 *ei = eh + 12 + i * 12;
            u32 ei_block = le32(ei + 0);
            if (ei_block <= logical) {
                child = ((u64)le16(ei + 8) << 32) | le32(ei + 4);
            }

            }
        }
        if (!child || read_block(child, node) < 0)
            return 0;
        eh = node;
    }
    return 0;
}

/* Read up to n bytes of file `ino` starting at byte offset `off`. */
long ext4_pread(u32 ino, void *buf, u64 off, u64 n)
{
    u8 inode[160];
    if (read_inode(ino, inode) < 0)
        return -1;
    u64 size = inode_size_bytes(inode);
    if (off >= size)
        return 0;
    u64 want = size - off;
    if (want > n)
        want = n;

    u8 *out = buf;
    u8 blk[4096];
    u64 done = 0;
    while (done < want) {
        u64 fpos = off + done;
        u32 logical = (u32)(fpos / fs.block_size);
        u32 within = (u32)(fpos % fs.block_size);
        u32 chunk = fs.block_size - within;
        if (chunk > want - done)
            chunk = (u32)(want - done);

        u64 phys = extent_map(inode, logical);
        if (phys == 0) {
            for (u32 i = 0; i < chunk; i++)
                out[done + i] = 0;
        } else {
            if (read_block(phys, blk) < 0)
                return -1;
            memcpy(out + done, blk + within, chunk);
        }
        done += chunk;
    }
    return (long)want;
}

long ext4_read(u32 ino, void *buf, u64 maxlen, u64 *out_size)
{
    if (out_size)
        *out_size = ext4_size(ino);
    return ext4_pread(ino, buf, 0, maxlen);
}

u64 ext4_size(u32 ino)
{
    u8 inode[160];
    if (read_inode(ino, inode) < 0)
        return 0;
    return inode_size_bytes(inode);
}

int ext4_is_dir(u32 ino)
{
    u8 inode[160];
    if (read_inode(ino, inode) < 0)
        return 0;
    u16 mode = le16(inode + 0);
    return (mode & 0xF000) == 0x4000;   /* S_IFDIR */
}

int ext4_readdir_from(u32 dir_ino, u64 *offp,
                      int (*cb)(const char *, u32, u8, void *), void *arg)
{
    u8 inode[160];
    if (read_inode(dir_ino, inode) < 0)
        return -1;
    u64 size = inode_size_bytes(inode);
    u8 blk[4096];
    char name[256];
    u64 off = offp ? *offp : 0;
    if (off > size)
        off = size;

    while (off < size) {
        u64 block_base = off & ~((u64)fs.block_size - 1);
        u32 pos = (u32)(off - block_base);
        u64 phys = extent_map(inode, (u32)(block_base / fs.block_size));
        if (phys == 0)
        {
            off = block_base + fs.block_size;
            continue;
        }
        if (read_block(phys, blk) < 0)
            return -1;
        while (pos < fs.block_size) {
            u32 child = le32(blk + pos);
            u16 rec_len = le16(blk + pos + 4);
            u8  name_len = blk[pos + 6];
            u8  ftype = blk[pos + 7];
            if (rec_len < 8)
                goto done;
            u64 next = block_base + pos + rec_len;
            if (child != 0 && name_len > 0) {
                memcpy(name, blk + pos + 8, name_len);
                name[name_len] = '\0';
                if (cb(name, child, ftype, arg)) {
                    if (offp)
                        *offp = off;
                    return 0;
                }
            }
            off = next;
            pos += rec_len;
        }
        if (off < block_base + fs.block_size)
            off = block_base + fs.block_size;
    }
done:
    if (offp)
        *offp = off;
    return 0;
}

int ext4_readdir(u32 dir_ino, int (*cb)(const char *, u32, u8, void *), void *arg)
{
    u64 off = 0;
    return ext4_readdir_from(dir_ino, &off, cb, arg);
}

struct find_ctx {
    const char *name;
    u32 len;
    u32 found;
};

static int find_cb(const char *name, u32 ino, u8 type, void *arg)
{
    (void)type;
    struct find_ctx *c = arg;
    if (strlen(name) == c->len && memcmp(name, c->name, c->len) == 0) {
        c->found = ino;
        return 1;
    }
    return 0;
}

static u32 dir_find(u32 dir_ino, const char *name, u32 len)
{
    if (len < sizeof(lookup_cache[0].name)) {
        for (int i = 0; i < EXT4_LOOKUP_CACHE; i++) {
            struct lookup_cache_entry *e = &lookup_cache[i];
            if (!e->valid || e->parent != dir_ino || e->len != len)
                continue;
            if (memcmp(e->name, name, len) == 0 && e->name[len] == 0)
                return e->ino;
        }
    }

    struct find_ctx c = { name, len, 0 };
    ext4_readdir(dir_ino, find_cb, &c);
    if (c.found && len < sizeof(lookup_cache[0].name)) {
        struct lookup_cache_entry *e =
            &lookup_cache[lookup_cache_hand++ % EXT4_LOOKUP_CACHE];
        e->valid = 1;
        e->parent = dir_ino;
        e->ino = c.found;
        e->len = len;
        memcpy(e->name, name, len);
        e->name[len] = 0;
    }
    return c.found;
}

u32 ext4_lookup(const char *path)
{
    if (!fs.mounted)
        return 0;
    u32 ino = EXT4_ROOT_INO;
    const char *p = path;
    while (*p == '/')
        p++;
    while (*p) {
        const char *start = p;
        while (*p && *p != '/')
            p++;
        u32 len = (u32)(p - start);
        if (len > 0) {
            ino = dir_find(ino, start, len);
            if (ino == 0)
                return 0;
        }
        while (*p == '/')
            p++;
    }
    return ino;
}

