        status |= VIRTIO_STATUS_FEATURES_OK; wr(VIRTIO_MMIO_STATUS, status);
        if (!(rd(VIRTIO_MMIO_STATUS) & VIRTIO_STATUS_FEATURES_OK)) {
            printk("[virtio] FEATURES_OK rejected\n");
            return -1;
