        wr(VIRTIO_MMIO_QUEUE_DESC_LOW,    (u32)da);
        wr(VIRTIO_MMIO_QUEUE_DESC_HIGH,   (u32)(da >> 32));
        wr(VIRTIO_MMIO_DRIVER_DESC_LOW,   (u32)av);
        wr(VIRTIO_MMIO_DRIVER_DESC_HIGH,  (u32)(av >> 32));
        wr(VIRTIO_MMIO_DEVICE_DESC_LOW,   (u32)us);
        wr(VIRTIO_MMIO_DEVICE_DESC_HIGH,  (u32)(us >> 32));
        wr(VIRTIO_MMIO_QUEUE_READY, 1);
        status |= VIRTIO_STATUS_DRIVER_OK; wr(VIRTIO_MMIO_STATUS, status);
    } else {
        printk("[virtio] unsupported mmio version %u\n", version);
        return -1;
    }

