/* Physical frame allocator: a free list of 4 KiB pages.
 *
 * Each free page stores the link to the next free page in its first bytes, so
 * the allocator itself needs no separate metadata array.
 */
#include "kernel/types.h"
#include "kernel/param.h"
#include "kernel/mm.h"
#include "kernel/printk.h"

void *memset(void *dst, int c, size_t n);

struct run {
    struct run *next;
};

static struct run *freelist;
static u64 free_count;
static u64 page_base;
static u64 page_count;

#define MAX_REF_PAGES 262144
static u16 refcnt[MAX_REF_PAGES];

static long page_index(void *pa)
{
    u64 a = (u64)pa;
    if (a < page_base || a >= page_base + page_count * PGSIZE)
        return -1;
    return (long)((a - page_base) / PGSIZE);
}

void kref_page(void *pa)
{
    u64 a = (u64)pa;
    if (a & (PGSIZE - 1))
        panic("kref_page: misaligned %p", pa);
    long idx = page_index(pa);
    if (idx < 0 || (u64)idx >= page_count)
        panic("kref_page: unmanaged %p", pa);
    if (refcnt[idx] == 0)
        panic("kref_page: free page %p", pa);
    refcnt[idx]++;
}

void kfree_page(void *pa)
{
    u64 a = (u64)pa;
    if (a & (PGSIZE - 1))
        panic("kfree_page: misaligned %p", pa);
    long idx = page_index(pa);
    if (idx < 0 || (u64)idx >= page_count)
        panic("kfree_page: unmanaged %p", pa);
    if (refcnt[idx] == 0)
        panic("kfree_page: double free %p", pa);
    if (--refcnt[idx] > 0)
        return;

    /* Poison to catch use-after-free during early bring-up. */
    memset(pa, 1, PGSIZE);

    struct run *r = (struct run *)pa;
    r->next = freelist;
    freelist = r;
    free_count++;
}

void *kalloc_page(void)
{
    struct run *r = freelist;
    if (!r)
        return NULL;
    freelist = r->next;
    free_count--;
    long idx = page_index(r);
    if (idx < 0 || (u64)idx >= page_count)
        panic("kalloc_page: unmanaged %p", r);
    if (refcnt[idx] != 0)
        panic("kalloc_page: allocated ref %p", r);
    refcnt[idx] = 1;
    memset(r, 0, PGSIZE);
    return r;
}

u64 pmm_free_pages(void)
{
    return free_count;
}

void pmm_init(u64 ram_start, u64 ram_end)
{
    u64 p = PGROUNDUP(ram_start);
    ram_end = PGROUNDDOWN(ram_end);
    page_base = p;
    page_count = (ram_end - page_base) / PGSIZE;
    if (page_count > MAX_REF_PAGES)
        panic("pmm_init: too many pages %lu", (unsigned long)page_count);
    for (; p + PGSIZE <= ram_end; p += PGSIZE) {
        refcnt[(p - page_base) / PGSIZE] = 1;
        kfree_page((void *)p);
    }

    printk("[pmm] %lu MiB free (%lu pages) in [%p, %p)\n",
           (unsigned long)(free_count * PGSIZE >> 20), (unsigned long)free_count,
           (void *)PGROUNDUP(ram_start), (void *)ram_end);
}
/* Kernel heap: address-ordered free-list allocator with coalescing.
 *
 * Backed by the physical frame allocator, grown one page at a time. Individual
 * allocations are bounded by one page (PGSIZE - header); page-sized or aligned
 * objects (e.g. page tables) should use kalloc_page() directly.
 */
#include "kernel/types.h"
#include "kernel/param.h"
#include "kernel/mm.h"
#include "kernel/printk.h"

void *memset(void *dst, int c, size_t n);

struct hdr {
    size_t      size;   /* total chunk size in bytes, including this header */
    struct hdr *next;   /* next free chunk (free list only) */
};

#define ALIGN_UP(n, a) (((n) + (a) - 1) & ~((size_t)(a) - 1))
#define HDR  ALIGN_UP(sizeof(struct hdr), 16)   /* 16-byte aligned header */
#define MINCHUNK (HDR + 16)

static struct hdr *freelist;   /* address-ordered */

static void insert_free(struct hdr *blk)
{
    struct hdr **pp = &freelist;
    while (*pp && *pp < blk)
        pp = &(*pp)->next;

    /* coalesce with successor */
    if (*pp && (char *)blk + blk->size == (char *)*pp) {
        blk->size += (*pp)->size;
        blk->next = (*pp)->next;
    } else {
        blk->next = *pp;
    }
    /* coalesce with predecessor */
    struct hdr *prev = (pp == &freelist) ? NULL : container_of(pp, struct hdr, next);
    if (prev && (char *)prev + prev->size == (char *)blk) {
        prev->size += blk->size;
        prev->next = blk->next;
    } else {
        *pp = blk;
    }
}

static int grow(void)
{
    void *page = kalloc_page();
    if (!page)
        return -1;
    struct hdr *blk = page;
    blk->size = PGSIZE;
    insert_free(blk);
    return 0;
}

void kheap_init(void)
{
    freelist = NULL;
    grow();
    printk("[kheap] initialised\n");
}

void *kmalloc(size_t n)
{
    if (n == 0)
        return NULL;
    size_t need = ALIGN_UP(n + HDR, 16);
    if (need > PGSIZE)
        panic("kmalloc: %lu too large (max %lu)", (unsigned long)n,
              (unsigned long)(PGSIZE - HDR));

    for (int attempt = 0; attempt < 2; attempt++) {
        struct hdr **pp = &freelist;
        for (; *pp; pp = &(*pp)->next) {
            struct hdr *cur = *pp;
            if (cur->size < need)
                continue;
            if (cur->size - need >= MINCHUNK) {
                struct hdr *rest = (struct hdr *)((char *)cur + need);
                rest->size = cur->size - need;
                rest->next = cur->next;
                cur->size = need;
                *pp = rest;
            } else {
                *pp = cur->next;
            }
            return (char *)cur + HDR;
        }
        if (grow() < 0)
            return NULL;
    }
    return NULL;
}

