/* LoongArch trap vector and timer plumbing. */
#include "kernel/types.h"
#include "kernel/trap.h"
#include "kernel/proc.h"
#include "kernel/loongarch.h"

volatile u64 g_ticks;

void tlbrvec(void);

void trap_init(void)
{
    w_eentry((u64)kernelvec);
    w_tlbrentry((u64)tlbrvec);
    w_euen(EUEN_FPE);
}

void timer_tick(void)
{
    g_ticks++;
    w_ticlr(1);
}

void timer_init(void)
{
    w_ticlr(1);
    w_tcfg(0);
    w_ecfg(r_ecfg() & ~ECFG_TIMER);
}

int dev_intr(u64 estat)
{
    if (ESTAT_ECODE(estat) != EXCCODE_INT)
        return 0;
    if (estat & ESTAT_TIMER) {
        timer_tick();
        return 2;
    }
    return 1;
}
/* LoongArch user trap handling and return path. */
#include "kernel/types.h"
#include "kernel/param.h"
#include "kernel/proc.h"
#include "kernel/trap.h"
#include "kernel/vm.h"
#include "kernel/syscall.h"
#include "kernel/loongarch.h"
#include "kernel/addr.h"
#include "kernel/printk.h"
#include "kernel/kio.h"

void la_userret(struct trapframe *tf) __attribute__((noreturn));

void usertrap(void)
{
    struct proc *p = myproc();
    p->trapframe->epc = r_era();

    u64 estat = r_estat();
    u64 ecode = ESTAT_ECODE(estat);
    if (ecode == EXCCODE_SYS) {
        p->trapframe->epc += 4;
        syscall();
    } else if (ecode == EXCCODE_INT) {
        int which = dev_intr(estat);
        if (which == 2)
            yield();
        else if (which == 0)
            printk("usertrap: unknown interrupt estat=%lx\n",
                   (unsigned long)estat);
    } else if (proc_handle_page_fault(r_badv()) == 0) {
        /* Shared-VM threads have per-thread roots; sync pages on demand. */
    } else {
        printk("usertrap: fault ecode=%lu era=%lx badv=%lx (pid %d) -> kill\n",
               (unsigned long)ecode, (unsigned long)r_era(),
               (unsigned long)r_badv(), p->pid);
        proc_exit(-1);
    }

    if (p->killed)
        proc_exit_signal(p->killed);

    usertrapret();
}

void usertrapret(void)
{
    struct proc *p = myproc();
    arch_intr_off();

    w_save0((u64)p->trapframe);
    w_save1(p->kstack + KSTACK_SIZE);
    w_pgdl(kva_to_pa((u64)p->pagetable));
    w_pgdh(0);
    w_asid((u64)(p->pid & 0x3ff));
    loongarch_invtlb_all();

    w_era(p->trapframe->epc);
    w_prmd(PRMD_PPLV3 | PRMD_PIE);
    la_userret(p->trapframe);
}

void forkret(void)
{
    usertrapret();
}
/* LoongArch64 user page tables.
 *
 * The kernel itself runs from the cached direct-map window (0x9...), while
 * user addresses are translated through software-filled TLB entries.  Page
 * directories store raw physical page addresses; leaf PTEs use LoongArch's
 * TLB entry format so the refill handler can load them directly.
 */
#include "kernel/types.h"
#include "kernel/param.h"
#include "kernel/memlayout.h"
#include "kernel/mm.h"
#include "kernel/proc.h"
#include "kernel/vm.h"
#include "kernel/addr.h"
#include "kernel/loongarch.h"
#include "kernel/printk.h"

void *memmove(void *dst, const void *src, size_t n);

#define PX(level, va)  (((va) >> (12 + 9 * (level))) & 0x1ff)

#define LA_PTE_V      (1UL << 0)
#define LA_PTE_D      (1UL << 1)
#define LA_PTE_PLV3   (3UL << 2)
#define LA_PTE_MAT_CC (1UL << 4)
#define LA_PTE_PPN(pa) (((pa) & 0x0000fffffffff000UL))
#define LA_PTE_PA(pte) ((pte) & 0x0000fffffffff000UL)
#define LA_PTE_COW    (1UL << 60)
#define LA_PTE_NR     (1UL << 61)
#define LA_PTE_NX     (1UL << 62)

static u64 make_leaf(u64 kva, int perm)
{
    u64 pte = LA_PTE_PPN(kva_to_pa(kva)) | LA_PTE_V | LA_PTE_PLV3 |
              LA_PTE_MAT_CC;
    if (perm & PERM_W)
        pte |= LA_PTE_D;
    if ((perm & PERM_R) == 0)
        pte |= LA_PTE_NR;
    if ((perm & PERM_X) == 0)
        pte |= LA_PTE_NX;
    return pte;
}

static int leaf_perm(u64 pte)
{
    int perm = PERM_U;
    if ((pte & LA_PTE_NR) == 0)
        perm |= PERM_R;
    if (pte & LA_PTE_D)
        perm |= PERM_W;
    if ((pte & LA_PTE_NX) == 0)
        perm |= PERM_X;
    return perm;
}

static u64 *walk(pagetable_t pt, u64 va, int alloc)
{
    if (va >= MAXVA)
        return NULL;
    for (int level = 2; level > 0; level--) {
        u64 *pde = &pt[PX(level, va)];
        if (*pde) {
            pt = (pagetable_t)pa_to_kva(*pde);
        } else {
            if (!alloc)
                return NULL;
            void *np = kalloc_page();
            if (!np)
                return NULL;
            *pde = kva_to_pa((u64)np);
            pt = np;
        }
    }
    return &pt[PX(0, va)];
}

int mappages(pagetable_t pt, u64 va, u64 size, u64 pa, int perm)
{
    if (size == 0)
        return -1;
    u64 a = PGROUNDDOWN(va);
    u64 last = PGROUNDDOWN(va + size - 1);
    for (;;) {
        u64 *pte = walk(pt, a, 1);
        if (!pte)
            return -1;
        if (*pte & LA_PTE_V)
            return -1;
        *pte = make_leaf(pa, perm);
        if (a == last)
            break;
        a += PGSIZE;
        pa += PGSIZE;
    }
    return 0;
}

u64 walkaddr(pagetable_t pt, u64 va)
{
    u64 *pte = walk(pt, va, 0);
    if (!pte || !(*pte & LA_PTE_V))
        return 0;
    return (u64)pa_to_kva(LA_PTE_PA(*pte));
}

pagetable_t uvmcreate(void)
{
    return (pagetable_t)kalloc_page();
}

u64 uvmalloc(pagetable_t pt, u64 oldsz, u64 newsz, int perm)
{
    if (newsz <= oldsz)
        return oldsz;
    for (u64 a = PGROUNDUP(oldsz); a < newsz; a += PGSIZE) {
        if (walkaddr(pt, a) != 0)
            continue;
        void *mem = kalloc_page();
        if (!mem)
            return 0;
        if (mappages(pt, a, PGSIZE, (u64)mem, perm | PERM_U) < 0) {
            kfree_page(mem);
            return 0;
        }
    }
    return newsz;
}

void uvmunmap(pagetable_t pt, u64 va, u64 npages, int do_free)
{
    for (u64 a = va; a < va + npages * PGSIZE; a += PGSIZE) {
        u64 *pte = walk(pt, a, 0);
        if (!pte || !(*pte & LA_PTE_V))
            continue;
        if (do_free)
            kfree_page(pa_to_kva(LA_PTE_PA(*pte)));
        *pte = 0;
    }
}

static void freewalk(pagetable_t pt)
{
    for (int i = 0; i < 512; i++) {
        u64 pte = pt[i];
        if (pte && (pte & LA_PTE_V) == 0) {
            freewalk((pagetable_t)pa_to_kva(pte));
            pt[i] = 0;
        }
    }
    kfree_page(pt);
}

void uvmfree(pagetable_t pt, u64 sz)
{
    if (sz > 0)
        uvmunmap(pt, 0, PGROUNDUP(sz) / PGSIZE, 1);
    freewalk(pt);
}

