int uvmcow(pagetable_t pt, u64 va)
{
    u64 a = PGROUNDDOWN(va);
    u64 *pte = walk(pt, a, 0);
    if (!pte || !(*pte & LA_PTE_V) || !(*pte & LA_PTE_COW))
        return 1;

    void *old = pa_to_kva(LA_PTE_PA(*pte));
    int perm = (leaf_perm(*pte) | PERM_W) & ~PERM_U;
    void *mem = kalloc_page();
    if (!mem)
        return -1;
    memmove(mem, old, PGSIZE);
    *pte = make_leaf((u64)mem, perm | PERM_U);
    kfree_page(old);
    loongarch_invtlb_all();
    return 0;
}

int uvmprotect(pagetable_t pt, u64 va, u64 len, int perm, int alloc_missing)
{
    if (len == 0)
        return 0;
    if (perm & PERM_W)
        perm |= PERM_R;
    int access = perm & (PERM_R | PERM_W | PERM_X);

    u64 start = PGROUNDDOWN(va);
    u64 end = PGROUNDUP(va + len);
    for (u64 a = start; a < end; a += PGSIZE) {
        u64 *pte = walk(pt, a, 0);
        if (!pte || !(*pte & LA_PTE_V)) {
            if (!alloc_missing)
                return -1;
            if (access == 0)
                continue;
            void *mem = kalloc_page();
            if (!mem)
                return -1;
            if (mappages(pt, a, PGSIZE, (u64)mem, perm | PERM_U) < 0) {
                kfree_page(mem);
                return -1;
            }
            continue;
        }

        if ((access & PERM_W) && (*pte & LA_PTE_COW)) {
            if (uvmcow(pt, a) < 0)
                return -1;
            pte = walk(pt, a, 0);
            if (!pte || !(*pte & LA_PTE_V))
                return -1;
        }

        u64 kva = (u64)pa_to_kva(LA_PTE_PA(*pte));
        if (access == 0) {
            kfree_page((void *)kva);
            *pte = 0;
            continue;
        }
        int keep_cow = (*pte & LA_PTE_COW) && !(access & PERM_W);
        *pte = make_leaf(kva, perm | PERM_U);
        if (keep_cow)
            *pte = (*pte & ~LA_PTE_D) | LA_PTE_COW;
    }
    loongarch_invtlb_all();
    return 0;
}

int uvmcopy(pagetable_t old, pagetable_t new, u64 start, u64 end)
{
    for (u64 a = PGROUNDDOWN(start); a < end; a += PGSIZE)
        if (uvmcopy_page(old, new, a) < 0)
            return -1;
    return 0;
}

int copyout(pagetable_t pt, u64 dstva, const void *src, u64 len)
{
    const char *s = src;
    while (len > 0) {
        u64 va0 = PGROUNDDOWN(dstva);
        if (uvmcow(pt, va0) < 0)
            return -1;
        u64 pa0 = walkaddr(pt, va0);
        if (pa0 == 0)
            return -1;
        u64 n = PGSIZE - (dstva - va0);
        if (n > len)
            n = len;
        memmove((void *)(pa0 + (dstva - va0)), s, n);
        len -= n;
        s += n;
        dstva = va0 + PGSIZE;
    }
    return 0;
}

int copyin(pagetable_t pt, void *dst, u64 srcva, u64 len)
{
    char *d = dst;
    while (len > 0) {
        u64 va0 = PGROUNDDOWN(srcva);
        u64 pa0 = walkaddr(pt, va0);
        if (pa0 == 0)
            return -1;
        u64 n = PGSIZE - (srcva - va0);
        if (n > len)
            n = len;
        memmove(d, (void *)(pa0 + (srcva - va0)), n);
        len -= n;
        d += n;
        srcva = va0 + PGSIZE;
    }
    return 0;
}

