void kvm_init(void)
{
    /* 4 KiB pages, 9-bit PT/DIR1/DIR2 indexes: PT=12, DIR1=21, DIR2=30. */
    u64 pwcl = (12UL << 0) | (9UL << 5) |
               (21UL << 10) | (9UL << 15) |
               (30UL << 20) | (9UL << 25);
    w_pwcl(pwcl);
    w_pwch(0);
    w_stlbps(12);
}

void kvm_enable(void)
{
    csr_write(0x180, DMW_VSEG9 | DMW_MAT_CC | DMW_PLV0);
    u64 crmd = r_crmd();
    crmd &= ~CRMD_DA;
    crmd |= CRMD_PG;
    w_crmd(crmd);
    loongarch_invtlb_all();
    printk("[mmu] LoongArch paging enabled (kernel DMW + user TLB refill)\n");
}

/* Minimal freestanding printf family for the kernel. */
#include "kernel/types.h"
#include "kernel/printk.h"
#include "kernel/kio.h"

typedef __builtin_va_list va_list;
#define va_start(ap, last) __builtin_va_start(ap, last)
#define va_arg(ap, type)   __builtin_va_arg(ap, type)
#define va_end(ap)         __builtin_va_end(ap)
#define va_copy(d, s)      __builtin_va_copy(d, s)

size_t strlen(const char *s);

/* Output sink: either a bounded buffer (snprintk) or the console (printk). */
struct sink {
    char  *buf;     /* NULL => write to console */
    size_t size;    /* capacity including NUL */
    size_t pos;     /* chars produced (may exceed size) */
};

static void emit(struct sink *s, char c)
{
    if (s->buf) {
        if (s->pos + 1 < s->size)
            s->buf[s->pos] = c;
    } else {
        uart_putc(c);
    }
    s->pos++;
}

static void emit_str(struct sink *s, const char *str)
{
    if (!str)
        str = "(null)";
    while (*str)
        emit(s, *str++);
}

static void emit_num(struct sink *s, u64 val, unsigned base, bool neg,
                     bool upper, int width, char pad)
{
    char tmp[32];
    const char *digits = upper ? "0123456789ABCDEF" : "0123456789abcdef";
    int i = 0;

    if (val == 0)
        tmp[i++] = '0';
    while (val) {
        tmp[i++] = digits[val % base];
        val /= base;
    }
    if (neg)
        tmp[i++] = '-';

    while (i < width--) /* pad to field width */
        emit(s, pad);
    while (i > 0)
        emit(s, tmp[--i]);
}

static void do_format(struct sink *s, const char *fmt, va_list ap)
{
    for (; *fmt; fmt++) {
        if (*fmt != '%') {
            emit(s, *fmt);
            continue;
        }
        fmt++;

        char pad = ' ';
        int width = 0;
        int longn = 0;

        if (*fmt == '0') {
            pad = '0';
            fmt++;
        }
        while (*fmt >= '0' && *fmt <= '9') {
            width = width * 10 + (*fmt - '0');
            fmt++;
        }
        while (*fmt == 'l') {
            longn++;
            fmt++;
        }
        if (*fmt == 'z') {
            longn = 1;
            fmt++;
        }

        switch (*fmt) {
        case 'd': {
            i64 v = longn ? va_arg(ap, i64) : va_arg(ap, int);
            bool neg = v < 0;
            u64 mag = neg ? (u64)(-v) : (u64)v;
            emit_num(s, mag, 10, neg, false, width, pad);
            break;
        }
        case 'u': {
            u64 v = longn ? va_arg(ap, u64) : va_arg(ap, unsigned);
            emit_num(s, v, 10, false, false, width, pad);
            break;
        }
        case 'x':
        case 'X': {
            u64 v = longn ? va_arg(ap, u64) : va_arg(ap, unsigned);
            emit_num(s, v, 16, false, *fmt == 'X', width, pad);
            break;
        }
        case 'p': {
            u64 v = (u64)(uintptr_t)va_arg(ap, void *);
            emit_str(s, "0x");
            emit_num(s, v, 16, false, false, width, pad);
            break;
        }
        case 'c':
            emit(s, (char)va_arg(ap, int));
            break;
        case 's':
            emit_str(s, va_arg(ap, const char *));
            break;
        case '%':
            emit(s, '%');
            break;
        case '\0':
            return;
        default:
            emit(s, '%');
            emit(s, *fmt);
            break;
        }
    }
}

int vsnprintk(char *buf, size_t size, const char *fmt, va_list ap)
{
    struct sink s = { .buf = buf, .size = size, .pos = 0 };
    do_format(&s, fmt, ap);
    if (buf && size)
        buf[s.pos < size ? s.pos : size - 1] = '\0';
    return (int)s.pos;
}

int snprintk(char *buf, size_t size, const char *fmt, ...)
{
    va_list ap;
    va_start(ap, fmt);
    int n = vsnprintk(buf, size, fmt, ap);
    va_end(ap);
    return n;
}

void printk(const char *fmt, ...)
{
    struct sink s = { .buf = NULL, .size = 0, .pos = 0 };
    va_list ap;
    va_start(ap, fmt);
    do_format(&s, fmt, ap);
    va_end(ap);
}

void panic(const char *fmt, ...)
{
    struct sink s = { .buf = NULL, .size = 0, .pos = 0 };
    va_list ap;
    emit_str(&s, "\n[panic] ");
    va_start(ap, fmt);
    do_format(&s, fmt, ap);
    va_end(ap);
    emit(&s, '\n');
    arch_halt();
}
/* Freestanding string / memory routines. */
#include "kernel/types.h"

void *memset(void *dst, int c, size_t n)
{
    unsigned char *p = dst;
    while (n--)
        *p++ = (unsigned char)c;
    return dst;
}

void *memcpy(void *dst, const void *src, size_t n)
{
    unsigned char *d = dst;
    const unsigned char *s = src;
    while (n--)
        *d++ = *s++;
    return dst;
}

void *memmove(void *dst, const void *src, size_t n)
{
    unsigned char *d = dst;
    const unsigned char *s = src;
    if (d < s) {
        while (n--)
            *d++ = *s++;
    } else {
        d += n;
        s += n;
        while (n--)
            *--d = *--s;
    }
    return dst;
}

int memcmp(const void *a, const void *b, size_t n)
{
    const unsigned char *x = a, *y = b;
    while (n--) {
        if (*x != *y)
            return *x - *y;
        x++;
        y++;
    }
    return 0;
}

size_t strlen(const char *s)
{
    size_t n = 0;
    while (s[n])
        n++;
    return n;
}

int strcmp(const char *a, const char *b)
{
    while (*a && *a == *b) {
        a++;
        b++;
    }
    return (unsigned char)*a - (unsigned char)*b;
}

int strncmp(const char *a, const char *b, size_t n)
{
    while (n && *a && *a == *b) {
        a++;
        b++;
        n--;
    }
    if (n == 0)
        return 0;
    return (unsigned char)*a - (unsigned char)*b;
}

char *strcpy(char *dst, const char *src)
{
    char *d = dst;
    while ((*d++ = *src++))
        ;
    return dst;
}

size_t strlcpy(char *dst, const char *src, size_t size)
{
    size_t srclen = strlen(src);
    if (size) {
        size_t n = srclen < size - 1 ? srclen : size - 1;
        memcpy(dst, src, n);
        dst[n] = '\0';
    }
    return srclen;
}

char *strchr(const char *s, int c)
{
    for (; *s; s++)
        if (*s == (char)c)
            return (char *)s;
    return c == 0 ? (char *)s : NULL;
}
